// Data updates throughout the day; ISR keeps pages fresh without forcing per-request SSR.
export const revalidate = 1800;

import { IndustryRadarChart } from "@/components/ui/charts/industry-radar-chart";
import { CompanyOverview } from "@/components/ui/company-overview";
import { CompanyAvgSalaryGraph } from "@/components/ui/charts/company-avg-salary-graph";
import { CompanyCard } from "@/components/ui/company-card";
import { CompaniesFilterBar } from "@/components/ui/filters/companies-filter-bar";
import { HeroStatsDashboard } from "@/components/ui/companies/hero-stats-dashboard";
import { ComparisonPanelWrapper } from "@/components/ui/companies/comparison-panel-wrapper";

import { companiesSearchParamsCache } from "@/lib/companies-search-params";
import { slugify } from "@/lib/slugify";

import {
  getAllCompanyData,
  getAverageCompanySalary,
  getTopCompaniesBySize,
  getAvgSalaryPerEmployeeForTop10Fortune,
  getCompaniesHeroStats,
} from "@/db/queries";

import { Suspense } from "react";
import Link from "next/link";
import { PaginationControls } from "@/components/ui/skills/pagination-controls";

type PageProps = {
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>;
};

export default async function CompaniesPage({ searchParams }: PageProps) {
  const filters = await companiesSearchParamsCache.parse(searchParams);
  const page =
    typeof filters.page === "string"
      ? parseInt(filters.page)
      : filters.page || 1;
  const limit = 50;
  const offset = (page - 1) * limit;

  // Parallel data fetching - all queries run simultaneously
  const [companiesRaw, salaryResults, , fortuneResults, heroStats] =
    await Promise.all([
      getAllCompanyData({
        limit,
        offset,
        search: filters.q,
        location: filters.location,
        companySize: filters.companySize,
        minSalary: filters.minSalary,
        minPostings: filters.minPostings,
        sort: filters.sort,
      }),
      getAverageCompanySalary(),
      getTopCompaniesBySize(),
      getAvgSalaryPerEmployeeForTop10Fortune(),
      getCompaniesHeroStats(),
    ]);

  // Database query returns limit+1 rows to check for next page
  const hasNextPage = companiesRaw.length > limit;
  const hasPrevPage = page > 1;

  // Process companies (take only 'limit' items, not limit+1)
  // No filtering needed since query now filters at database level
  const companies = companiesRaw.slice(0, limit).map((company: any) => ({
    ...company,
    postings_count: Number(company.postings_count ?? 0),
    median_salary: Number(company.median_salary ?? company.avg_salary ?? 0),
    avg_salary: Number(company.median_salary ?? company.avg_salary ?? 0),
    company_size: company.company_size?.toString() || "N/A",
    slug: slugify(company.name ?? ""),
  }));

  const salaryData = salaryResults.slice(0, 10).map((row: any) => ({
    company: row.company,
    median_salary: Number(row.median_salary ?? row.avg_salary ?? 0),
    avg_salary: Number(row.median_salary ?? row.avg_salary ?? 0),
    posting_count: Number(row.posting_count ?? 0),
  }));

  const fortuneData = fortuneResults.map((row: any) => ({
    company: row.company,
    median_salary: Number(row.median_salary ?? row.avg_salary ?? 0),
    avg_salary: Number(row.median_salary ?? row.avg_salary ?? 0),
    employee_count: Number(row.employee_count ?? 0),
    fortune_rank: Number(row.fortune_rank ?? 0),
    posting_count: Number(row.posting_count ?? 0),
  }));

  const globalMedian = Number(
    salaryResults[0]?.global_median_salary ?? salaryResults[0]?.global_avg_salary ?? 0,
  );

  const buildPageUrl = (pageNum: number) => {
    const params = new URLSearchParams();
    params.set("page", pageNum.toString());
    if (filters.q) params.set("q", filters.q);
    if (filters.location) params.set("location", filters.location);
    if (filters.companySize.length > 0)
      params.set("companySize", filters.companySize.join(","));
    if (filters.minSalary > 0)
      params.set("minSalary", filters.minSalary.toString());
    if (filters.minPostings > 0)
      params.set("minPostings", filters.minPostings.toString());
    if (filters.sort !== "postings") params.set("sort", filters.sort);
    return `/companies?${params.toString()}`;
  };

  return (
    <div className="container mx-auto p-6 space-y-8 pb-16">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div className="max-w-2xl space-y-2">
          <h1 className="text-4xl font-black tracking-tight lg:text-5xl">
            Company Explorer
          </h1>
        </div>
      </div>

      {/* Hero Stats Dashboard */}
      <HeroStatsDashboard stats={heroStats} />

      {/* Company Filters */}
      <CompaniesFilterBar />

      <Suspense
        fallback={<div className="h-28 rounded-xl bg-muted animate-pulse" />}
      >
        <CompanyOverview />
      </Suspense>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
        <div className="rounded-2xl border bg-card p-6 shadow-sm">
          <div className="flex items-start justify-between mb-4">
            <div>
              <h3 className="text-lg font-bold">Median Salary Benchmarks</h3>
              <p className="text-sm text-muted-foreground">
                Top companies by median salary
              </p>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-primary">
                $
                {globalMedian.toLocaleString(undefined, {
                  maximumFractionDigits: 0,
                })}
              </div>
              <div className="text-xs text-muted-foreground">
                Global median
              </div>
            </div>
          </div>
          <CompanyAvgSalaryGraph
            data={salaryData}
            globalMedian={globalMedian}
            fortuneData={fortuneData}
          />
        </div>

        <div className="rounded-2xl border bg-card p-6 shadow-sm">
          <div className="flex items-start justify-between mb-4">
            <div>
              <h3 className="text-lg font-bold">Market Concentration</h3>
              <p className="text-sm text-muted-foreground">
                Industry distribution across segments
              </p>
            </div>
            <div className="text-xs text-muted-foreground">Live</div>
          </div>
          <div className="h-64">
            <IndustryRadarChart />
          </div>
        </div>
      </div>

      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Top Companies</h2>
      </div>

      <ComparisonPanelWrapper companies={companies} offset={offset} />

      {/* Pagination Controls */}
      {(hasNextPage || hasPrevPage) && (
        <div className="flex flex-col sm:flex-row items-center justify-between py-6 border-t border-slate-200 dark:border-slate-800 gap-4">
          <p className="text-sm text-slate-500 dark:text-slate-400">
            Showing{" "}
            <span className="font-bold text-slate-900 dark:text-white">
              {offset + 1}
            </span>{" "}
            to{" "}
            <span className="font-bold text-slate-900 dark:text-white">
              {offset + companies.length}
            </span>{" "}
            of many companies
          </p>
          <PaginationControls
            currentPage={page}
            hasNextPage={hasNextPage}
            hasPrevPage={hasPrevPage}
            buildPageUrl={buildPageUrl}
          />
        </div>
      )}
    </div>
  );
}

// Data updates throughout the day; ISR keeps pages fresh without forcing per-request SSR.
export const revalidate = 1800;

import { notFound } from "next/navigation";
import {
  getLocationStats,
  getTopSkillsByLocation,
  getTopCompaniesByLocation,
  getRecentJobsByLocation,
} from "@/db/queries";
import { formatSalary } from "@/lib/location-utils";

// Import new enhanced components
import { EnhancedHero } from "@/components/location/EnhancedHero";
import { AnimatedStatCard } from "@/components/location/AnimatedStatCard";
import { MarketHealthCard } from "@/components/location/MarketHealthCard";
import { SalaryDistributionChart } from "@/components/location/SalaryDistributionChart";
import { WorkModeChart } from "@/components/location/WorkModeChart";
import { SkillsVisualization } from "@/components/location/SkillsVisualization";
import { CompaniesChart } from "@/components/location/CompaniesChart";
import { MarketInsightsPanel } from "@/components/location/MarketInsightsPanel";
import { JobsSection } from "@/components/location/JobsSection";

interface PageProps {
  params: Promise<{ slug: string }>;
}

// Map full state names to abbreviations
const STATE_ABBREVIATIONS: Record<string, string> = {
  alabama: "al",
  alaska: "ak",
  arizona: "az",
  arkansas: "ar",
  california: "ca",
  colorado: "co",
  connecticut: "ct",
  delaware: "de",
  florida: "fl",
  georgia: "ga",
  hawaii: "hi",
  idaho: "id",
  illinois: "il",
  indiana: "in",
  iowa: "ia",
  kansas: "ks",
  kentucky: "ky",
  louisiana: "la",
  maine: "me",
  maryland: "md",
  massachusetts: "ma",
  michigan: "mi",
  minnesota: "mn",
  mississippi: "ms",
  missouri: "mo",
  montana: "mt",
  nebraska: "ne",
  nevada: "nv",
  "new-hampshire": "nh",
  "new-jersey": "nj",
  "new-mexico": "nm",
  "new-york": "ny",
  "north-carolina": "nc",
  "north-dakota": "nd",
  ohio: "oh",
  oklahoma: "ok",
  oregon: "or",
  pennsylvania: "pa",
  "rhode-island": "ri",
  "south-carolina": "sc",
  "south-dakota": "sd",
  tennessee: "tn",
  texas: "tx",
  utah: "ut",
  vermont: "vt",
  virginia: "va",
  washington: "wa",
  "west-virginia": "wv",
  wisconsin: "wi",
  wyoming: "wy",
  "district-of-columbia": "dc",
  "puerto-rico": "pr",
};

export default async function LocationDetailPage({ params }: PageProps) {
  const { slug: locationSlug } = await params;

  if (!locationSlug) {
    notFound();
  }

  // Enhanced slug resolution with state abbreviation handling
  async function resolveStatsAndSlug(slug: string) {
    console.log("🔍 Attempting to resolve slug:", slug);

    // Strategy 1: Try exact slug match
    let stats = await getLocationStats(slug);
    if (stats) {
      console.log("✅ Found with exact match:", slug);
      return { stats, slugUsed: slug };
    }

    // Strategy 2: Convert full state name to abbreviation
    // Expected format: city-state-country or city-state
    const parts = slug.split("-");

    // Try to identify and replace state name with abbreviation
    for (let i = 0; i < parts.length; i++) {
      const potentialState = parts[i];

      // Check if this part is a full state name
      if (STATE_ABBREVIATIONS[potentialState]) {
        const abbreviatedParts = [...parts];
        abbreviatedParts[i] = STATE_ABBREVIATIONS[potentialState];
        const abbreviatedSlug = abbreviatedParts.join("-");

        console.log(
          `🔄 Trying with abbreviated state (${potentialState} → ${STATE_ABBREVIATIONS[potentialState]}):`,
          abbreviatedSlug,
        );
        stats = await getLocationStats(abbreviatedSlug);
        if (stats) {
          console.log("✅ Found with state abbreviation:", abbreviatedSlug);
          return { stats, slugUsed: abbreviatedSlug };
        }

        // Also try without the country code
        if (abbreviatedParts.length > 2) {
          const withoutCountry = abbreviatedParts.slice(0, -1).join("-");
          console.log("🔄 Trying abbreviated without country:", withoutCountry);
          stats = await getLocationStats(withoutCountry);
          if (stats) {
            console.log(
              "✅ Found abbreviated without country:",
              withoutCountry,
            );
            return { stats, slugUsed: withoutCountry };
          }
        }
      }
    }

    // Strategy 3: Try progressively shorter slug candidates
    for (let len = parts.length - 1; len >= 1; len--) {
      const candidate = parts.slice(0, len).join("-");
      console.log("🔄 Trying shorter slug:", candidate);

      stats = await getLocationStats(candidate);
      if (stats) {
        console.log("✅ Found with shorter slug:", candidate);
        return { stats, slugUsed: candidate };
      }
    }

    // Strategy 4: Try without country code (last part if it looks like a country code)
    if (parts.length > 2 && parts[parts.length - 1].length === 2) {
      const withoutCountry = parts.slice(0, -1).join("-");
      console.log("🔄 Trying without country code:", withoutCountry);

      stats = await getLocationStats(withoutCountry);
      if (stats) {
        console.log("✅ Found without country code:", withoutCountry);
        return { stats, slugUsed: withoutCountry };
      }
    }

    console.log("❌ No match found for slug:", slug);
    return { stats: null, slugUsed: slug };
  }

  const { stats, slugUsed } = await resolveStatsAndSlug(locationSlug);

  if (!stats) {
    console.error("Location not found:", {
      originalSlug: locationSlug,
      attemptedSlug: slugUsed,
    });
    notFound();
  }

  const [topSkills, topCompanies, recentJobs] = await Promise.all([
    getTopSkillsByLocation(slugUsed),
    getTopCompaniesByLocation(slugUsed),
    getRecentJobsByLocation(slugUsed, 10),
  ]);

  const locationName = [stats.city, stats.state, stats.country]
    .filter(Boolean)
    .join(", ");

  return (
    <div className="container mx-auto py-8 px-4">
      {/* Enhanced Hero with quick stats */}
      <EnhancedHero
        locationName={locationName}
        stats={stats}
        recentJobs={recentJobs}
      />

      {/* Market Health Score + Key Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <MarketHealthCard stats={stats} />
        <AnimatedStatCard
          icon="briefcase"
          label="Total Jobs"
          value={Number(stats.totalJobs)}
          trend={8}
          gradientFrom="from-blue-500"
          gradientTo="to-blue-600"
        />
        <AnimatedStatCard
          icon="building"
          label="Active Companies"
          value={Number(stats.totalCompanies)}
          trend={5}
          gradientFrom="from-purple-500"
          gradientTo="to-purple-600"
        />
      </div>

      {/* Salary Distribution Chart */}
      <div className="mb-8">
        <SalaryDistributionChart
          avgMinSalary={stats.medianMinSalary ?? stats.avgMinSalary}
          avgMedSalary={stats.medianSalary ?? stats.avgMedSalary}
          avgMaxSalary={stats.medianMaxSalary ?? stats.avgMaxSalary}
        />
      </div>

      {/* Charts Row 1: Work Mode & Skills */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        <WorkModeChart jobs={recentJobs} />
        <SkillsVisualization skills={topSkills} />
      </div>

      {/* Charts Row 2: Companies & Market Insights */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        <CompaniesChart companies={topCompanies} />
        <MarketInsightsPanel
          stats={stats}
          topSkills={topSkills}
          recentJobs={recentJobs}
        />
      </div>

      {/* Enhanced Jobs Section with Filters */}
      <div className="mt-8">
        <JobsSection jobs={recentJobs} />
      </div>
    </div>
  );
}

import Header from "../components/ui/Header";
import {
  getTrendingSkills,
  getTotalStats,
  getIndustryBreakdown,
  getTopHiringCompanies,
  getSalaryInsights,
  getRecentPostings,
  getExperienceDistribution,
} from "@/db/queries";

// Import home page components
import { HeroStats } from "@/components/ui/home/hero-stats";
import { IndustryBreakdownChart } from "@/components/ui/home/industry-breakdown-chart";
import { TopCompaniesGrid } from "@/components/ui/home/top-companies-grid";
import { ExperienceDonutChart } from "@/components/ui/home/experience-donut-chart";
import { SalaryInsightsPanel } from "@/components/ui/home/salary-insights-panel";
import { RecentActivityFeed } from "@/components/ui/home/recent-activity-feed";
import { QuickActionGrid } from "@/components/ui/home/quick-action-grid";
import { EnhancedTrendingSkills } from "@/components/ui/home/enhanced-trending-skills";

// Data updates throughout the day; ISR keeps pages fresh without forcing per-request SSR.
export const revalidate = 1800;

export default async function Home() {
  // Fetch all data in parallel
  const [
    statsData,
    industryData,
    companiesData,
    salaryData,
    recentPostings,
    experienceData,
    trendingSkillsRaw,
  ] = await Promise.all([
    getTotalStats(),
    getIndustryBreakdown(),
    getTopHiringCompanies(),
    getSalaryInsights(),
    getRecentPostings(),
    getExperienceDistribution(),
    getTrendingSkills(30, 10),
  ]);

  // Format trending skills for the enhanced chart
  const trendingSkills = trendingSkillsRaw.map((s: any) => ({
    skill_name: s.name ?? s.skill_name ?? "",
    current_count: s.current_count ?? s.currentCount ?? 0,
    previous_count: s.previous_count ?? s.previousCount ?? 0,
    growth_rate: Number(s.growth_percentage ?? s.growthRate ?? 0),
  }));

  return (
    <>
      <Header />

      <div className="container mx-auto px-4 py-8 space-y-8">
        {/* Hero Stats Section */}
        <section>
          <HeroStats data={statsData} />
        </section>

        {/* Quick Actions */}
        <section>
          <QuickActionGrid />
        </section>

        {/* Two Column Layout - Charts */}
        <section className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <IndustryBreakdownChart data={industryData} />
          <ExperienceDonutChart data={experienceData} />
        </section>

        {/* Salary Insights */}
        <section>
          <SalaryInsightsPanel data={salaryData} />
        </section>

        {/* Enhanced Trending Skills */}
        <section>
          <EnhancedTrendingSkills data={trendingSkills} />
        </section>

        {/* Two Column Layout - Companies & Recent Activity */}
        <section className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2">
            <TopCompaniesGrid data={companiesData} />
          </div>
          <div>
            <RecentActivityFeed data={recentPostings} />
          </div>
        </section>
      </div>
    </>
  );
}

// Data updates throughout the day; ISR keeps pages fresh without forcing per-request SSR.
export const revalidate = 1800;

import React, { Suspense } from "react";
import {
  getTopJobRoles,
  getTopRolesTimeSeries,
  getMedianSalary,
  getTopLocation,
  getRemotePercentage,
  getRoleDistribution,
  getSkillsFrequency,
  getPostingTimeline,
  getExperienceDistribution,
  getSalaryInsights,
  getRolesSalaryBenchmark,
} from "@/db/queries";
import RoleCard from "@/components/ui/role-card";
import { PaginationControls } from "@/components/ui/skills/pagination-controls";
import { StatsGrid } from "@/components/ui/roles/stats-grid";
import { RoleDistributionChart } from "@/components/ui/roles/role-distribution-chart";
import { SalaryByRoleChart } from "@/components/ui/roles/salary-by-role-chart";
import { MarketInsightsBar } from "@/components/ui/roles/market-insights-bar";
import { SkillsFrequencyChart } from "@/components/ui/roles/skills-frequency-chart";
import { PostingTimelineChart } from "@/components/ui/roles/posting-timeline-chart";
import { ExperienceBreakdownChart } from "@/components/ui/roles/experience-breakdown-chart";
import { slugify } from "@/lib/slugify";
import { searchParamsCache } from "@/lib/search-params";
import { FilterBar } from "@/components/ui/filters/filter-bar";

interface PageProps {
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>;
}

export default async function RolesPage({ searchParams }: PageProps) {
  try {
    const filters = await searchParamsCache.parse(searchParams);

    const roles = await getTopJobRoles(20, filters, Number(filters.page ?? 1));

    const [
      medianSalary,
      topLocation,
      remotePercentage,
      roleDistribution,
      skillsFrequency,
      postingTimeline,
      experienceDistribution,
      salaryInsights,
      salaryBenchmark,
    ] = await Promise.all([
      getMedianSalary(filters),
      getTopLocation(filters),
      getRemotePercentage(filters),
      getRoleDistribution(10, filters),
      getSkillsFrequency(20, filters),
      getPostingTimeline(90, filters),
      getExperienceDistribution(filters),
      getSalaryInsights(),
      getRolesSalaryBenchmark(8),
    ]);

    const tsRows = await getTopRolesTimeSeries(roles.length || 20);

    const timeseriesMap = new Map<string, { day: string; count: number }[]>();
    for (const row of tsRows) {
      const list = timeseriesMap.get(row.title) ?? [];
      list.push({ day: row.day, count: row.count });
      timeseriesMap.set(row.title, list);
    }

    // Salary lookup map for role cards
    const salaryMap = new Map(
      salaryBenchmark.map((r) => [r.title, r.median_salary ?? r.avg_salary]),
    );

    const totalRoles = roleDistribution.reduce((sum, r) => sum + r.count, 0);

    return (
      <div className="space-y-6">
        {/* Header */}
        <div className="pb-2">
          <h1 className="text-3xl font-bold mb-1">Explore Roles</h1>
          <p className="text-muted-foreground text-sm">
            {totalRoles.toLocaleString()} postings across all roles
          </p>
        </div>

        {/* Stats Grid */}
        <StatsGrid
          totalRoles={totalRoles}
          medianSalary={medianSalary}
          topLocation={{
            location: topLocation?.location ?? "N/A",
            count: topLocation?.count ?? 0,
          }}
          remotePercentage={remotePercentage}
        />

        {/* Market Pulse — synthesized insights */}
        <MarketInsightsBar
          highestPayingRole={salaryInsights.highestRole}
          highestSalary={salaryInsights.highestSalary}
          mostInDemandRole={roleDistribution[0]?.title ?? "N/A"}
          mostInDemandCount={roleDistribution[0]?.count ?? 0}
          medianSalary={salaryInsights.medianSalary}
          minSalary={salaryInsights.minSalary}
          maxSalary={salaryInsights.maxSalary}
        />

        {/* Salary Benchmark + Role Distribution side by side */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <SalaryByRoleChart data={salaryBenchmark} />
          <RoleDistributionChart data={roleDistribution} />
        </div>

        {/* Filter Bar */}
        <FilterBar />

        {/* Role Cards Grid */}
        <h2 className="text-2xl font-bold">Browse All Roles</h2>
        {roles.length > 0 ? (
          <div className="grid gap-4 sm:grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
            {roles.map((r: any) => (
              <RoleCard
                key={r.title}
                title={r.title}
                count={Number(r.count)}
                timeseries={timeseriesMap.get(r.title) ?? []}
                medianSalary={salaryMap.get(r.title)}
                href={
                  slugify(r.title) ? `/roles/${slugify(r.title)}` : undefined
                }
              />
            ))}
          </div>
        ) : (
          <div className="py-20 text-center border-2 border-dashed rounded-xl bg-muted/10">
            <p className="text-muted-foreground">
              No roles found matching your filters.
            </p>
          </div>
        )}

        {/* Pagination Controls */}
        <div className="flex items-center justify-between py-6 border-t border-slate-200 dark:border-slate-800">
          <div className="text-sm text-slate-500">Page {filters.page ?? 1}</div>
          <PaginationControls
            currentPage={Number(filters.page ?? 1)}
            hasNextPage={roles.length === 20}
            hasPrevPage={Number(filters.page ?? 1) > 1}
            buildPageUrl={(pageNum: number) => {
              const params = new URLSearchParams();
              if (filters.q) params.set("q", String(filters.q));
              if (filters.location)
                params.set("location", String(filters.location));
              if (filters.minSalary)
                params.set("minSalary", String(filters.minSalary));
              if (filters.experience && Array.isArray(filters.experience)) {
                for (const e of filters.experience)
                  params.append("experience", String(e));
              }
              params.set("page", String(pageNum));
              return `/roles?${params.toString()}`;
            }}
          />
        </div>

        {/* Deep Analytics — filter-aware */}
        <div className="mt-4 space-y-6">
          <div>
            <h2 className="text-2xl font-bold">Detailed Analytics</h2>
            <p className="text-sm text-muted-foreground mt-1">
              Reflects your current filters
            </p>
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <PostingTimelineChart data={postingTimeline} />
            <ExperienceBreakdownChart data={experienceDistribution} />
          </div>
          <SkillsFrequencyChart data={skillsFrequency} />
        </div>
      </div>
    );
  } catch (error) {
    throw error;
  }
}

"use client";

import { useState, useEffect } from "react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Search, X, SlidersHorizontal } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

interface JobFiltersProps {
  onFilterChange?: (filters: {
    search: string;
    workMode: string;
    experience: string;
    sortBy: string;
  }) => void;
  initialValues?: {
    search: string;
    workMode: string;
    experience: string;
    sortBy: string;
  };
}

export function JobFilters({ onFilterChange, initialValues }: JobFiltersProps) {
  const [search, setSearch] = useState(initialValues?.search || "");
  const [workMode, setWorkMode] = useState(initialValues?.workMode || "all");
  const [experience, setExperience] = useState(
    initialValues?.experience || "all",
  );
  const [sortBy, setSortBy] = useState(initialValues?.sortBy || "date");
  const [showFilters, setShowFilters] = useState(false);

  const activeFiltersCount =
    (workMode !== "all" ? 1 : 0) +
    (experience !== "all" ? 1 : 0) +
    (search.length > 0 ? 1 : 0);

  // Auto-apply filters with debouncing for search
  useEffect(() => {
    const timer = setTimeout(() => {
      onFilterChange?.({ search, workMode, experience, sortBy });
    }, 300); // 300ms debounce for search

    return () => clearTimeout(timer);
  }, [search, workMode, experience, sortBy, onFilterChange]);

  const handleClearFilters = () => {
    setSearch("");
    setWorkMode("all");
    setExperience("all");
    setSortBy("date");
    onFilterChange?.({
      search: "",
      workMode: "all",
      experience: "all",
      sortBy: "date",
    });
  };

  const handleApplyFilters = () => {
    onFilterChange?.({ search, workMode, experience, sortBy });
  };

  return (
    <div className="space-y-4 mb-6">
      {/* Main Search Bar */}
      <div className="flex gap-2">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <Input
            placeholder="Search job titles..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-10"
          />
        </div>
        <Button
          variant="outline"
          onClick={() => setShowFilters(!showFilters)}
          className="gap-2"
        >
          <SlidersHorizontal className="w-4 h-4" />
          Filters
          {activeFiltersCount > 0 && (
            <Badge variant="secondary" className="ml-1">
              {activeFiltersCount}
            </Badge>
          )}
        </Button>
      </div>

      {/* Expanded Filters */}
      <AnimatePresence>
        {showFilters && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
            className="overflow-hidden"
          >
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 p-4 bg-muted/50 rounded-lg">
              <div>
                <label className="text-sm font-medium mb-2 block">
                  Work Mode
                </label>
                <Select value={workMode} onValueChange={setWorkMode}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All</SelectItem>
                    <SelectItem value="remote">Remote</SelectItem>
                    <SelectItem value="hybrid">Hybrid</SelectItem>
                    <SelectItem value="onsite">On-site</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div>
                <label className="text-sm font-medium mb-2 block">
                  Experience Level
                </label>
                <Select value={experience} onValueChange={setExperience}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">All Levels</SelectItem>
                    <SelectItem value="entry">Entry Level</SelectItem>
                    <SelectItem value="mid">Mid Level</SelectItem>
                    <SelectItem value="senior">Senior Level</SelectItem>
                    <SelectItem value="lead">Lead/Principal</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div>
                <label className="text-sm font-medium mb-2 block">
                  Sort By
                </label>
                <Select value={sortBy} onValueChange={setSortBy}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="date">Most Recent</SelectItem>
                    <SelectItem value="salary">Highest Salary</SelectItem>
                    <SelectItem value="relevance">Most Relevant</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="flex justify-between items-center mt-4">
              <Button
                variant="ghost"
                size="sm"
                onClick={handleClearFilters}
                className="gap-1"
              >
                <X className="w-4 h-4" />
                Clear All
              </Button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Active Filters Display */}
      {activeFiltersCount > 0 && (
        <div className="flex flex-wrap gap-2">
          {search && (
            <Badge variant="secondary" className="gap-1">
              Search: {search}
              <X
                className="w-3 h-3 cursor-pointer"
                onClick={() => setSearch("")}
              />
            </Badge>
          )}
          {workMode !== "all" && (
            <Badge variant="secondary" className="gap-1">
              {workMode}
              <X
                className="w-3 h-3 cursor-pointer"
                onClick={() => setWorkMode("all")}
              />
            </Badge>
          )}
          {experience !== "all" && (
            <Badge variant="secondary" className="gap-1">
              {experience}
              <X
                className="w-3 h-3 cursor-pointer"
                onClick={() => setExperience("all")}
              />
            </Badge>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  TooltipProps,
} from "recharts";
import { formatSalary } from "@/lib/location-utils";
import { DollarSign } from "lucide-react";
import { useState } from "react";

interface SalaryDistributionChartProps {
  avgMinSalary?: number | string | null;
  avgMedSalary?: number | string | null;
  avgMaxSalary?: number | string | null;
}

// Custom Tooltip Component
interface CustomTooltipProps extends TooltipProps<number, string> {
  active?: boolean;
  payload?: Array<{
    name: string;
    value: number;
    payload: { name: string; value: number; fill: string };
  }>;
}

const CustomTooltip = ({ active, payload }: CustomTooltipProps) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    return (
      <div className="bg-popover border border-border rounded-lg shadow-lg p-3">
        <div className="flex items-center gap-2 mb-2">
          <div
            className="w-3 h-3 rounded-sm"
            style={{ backgroundColor: data.fill }}
          />
          <p className="font-bold text-sm text-foreground">{data.name}</p>
        </div>
        <p className="text-base font-semibold text-foreground">
          {formatSalary(data.value)}
        </p>
      </div>
    );
  }
  return null;
};

// Custom Bar Shape with Subtle Hover Effect
const CustomBar = (props: any) => {
  const { fill, x, y, width, height } = props;
  const [isHovered, setIsHovered] = useState(false);

  // Calculate the current opacity and scale based on hover state
  const opacity = isHovered ? 0.95 : 1;
  const scaleY = isHovered ? 1.02 : 1;
  const scaledHeight = height * scaleY;
  const offsetY = (height - scaledHeight) / 2;

  return (
    <g
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{
        filter: isHovered ? "brightness(1.1)" : "brightness(1)",
        transition: "filter 0.2s ease-in-out, transform 0.2s ease-in-out",
      }}
    >
      <rect
        x={x}
        y={y + offsetY}
        width={width}
        height={scaledHeight}
        fill={fill}
        rx={8}
        ry={8}
        opacity={opacity}
        style={{
          transition: "opacity 0.2s ease-in-out",
        }}
      />
    </g>
  );
};

export function SalaryDistributionChart({
  avgMinSalary,
  avgMedSalary,
  avgMaxSalary,
}: SalaryDistributionChartProps) {
  const data = [
    { name: "Minimum", value: Number(avgMinSalary || 0), fill: "#ef4444" },
    { name: "Median", value: Number(avgMedSalary || 0), fill: "#3b82f6" },
    { name: "Maximum", value: Number(avgMaxSalary || 0), fill: "#10b981" },
  ].filter((item) => item.value > 0);

  if (data.length === 0) {
    return (
      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <DollarSign className="w-5 h-5 text-green-500" />
            <CardTitle>Salary Distribution</CardTitle>
          </div>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground">No salary data available</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center gap-2">
          <DollarSign className="w-5 h-5 text-green-500" />
          <CardTitle>Salary Distribution</CardTitle>
        </div>
        <p className="text-sm text-muted-foreground">
          Median-centered salary ranges across all positions
        </p>
      </CardHeader>
      <CardContent>
        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={data}>
            <CartesianGrid
              strokeDasharray="3 3"
              stroke="rgb(148 163 184)"
              opacity={0.2}
            />
            <XAxis
              dataKey="name"
              className="text-xs"
              tick={{ fill: "rgb(148 163 184)" }}
              stroke="rgb(148 163 184)"
            />
            <YAxis
              tickFormatter={(value) => `$${(value / 1000).toFixed(0)}K`}
              className="text-xs"
              tick={{ fill: "rgb(148 163 184)" }}
              stroke="rgb(148 163 184)"
            />
            <Tooltip content={<CustomTooltip />} />
            <Bar dataKey="value" radius={[8, 8, 0, 0]} fill="#3b82f6" />
          </BarChart>
        </ResponsiveContainer>
      </CardContent>
    </Card>
  );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Legend,
  Tooltip,
  TooltipProps,
} from "recharts";
import { Briefcase } from "lucide-react";
import { calculateWorkModeDistribution } from "@/lib/location-analytics";

interface WorkModeChartProps {
  jobs: Array<{ remoteAllowed?: boolean | null }>;
}

const COLORS = {
  remote: "#10b981", // green
  hybrid: "#3b82f6", // blue
  onsite: "#6b7280", // gray
};

// Custom Tooltip Component
interface CustomTooltipProps extends TooltipProps<number, string> {
  active?: boolean;
  payload?: Array<{
    name: string;
    value: number;
    payload: { name: string; value: number; color: string };
  }>;
}

const CustomTooltip = ({ active, payload }: CustomTooltipProps) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    return (
      <div className="bg-popover border border-border rounded-lg shadow-lg p-4">
        <div className="flex items-center gap-2 mb-2">
          <div
            className="w-3 h-3 rounded-sm"
            style={{ backgroundColor: data.color }}
          />
          <p className="font-bold text-sm text-foreground">{data.name}</p>
        </div>
        <p className="text-sm text-muted-foreground">
          <span className="font-semibold text-foreground">{data.value}</span>{" "}
          jobs
        </p>
      </div>
    );
  }
  return null;
};

export function WorkModeChart({ jobs }: WorkModeChartProps) {
  const distribution = calculateWorkModeDistribution(jobs);

  const data = [
    { name: "Remote", value: distribution.remote, color: COLORS.remote },
    { name: "Hybrid", value: distribution.hybrid, color: COLORS.hybrid },
    { name: "On-site", value: distribution.onsite, color: COLORS.onsite },
  ].filter((item) => item.value > 0);

  if (data.length === 0 || jobs.length === 0) {
    return (
      <Card>
        <CardHeader>
          <div className="flex items-center gap-2">
            <Briefcase className="w-5 h-5 text-blue-500" />
            <CardTitle>Work Mode Distribution</CardTitle>
          </div>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground text-sm">
            No work mode data available
          </p>
        </CardContent>
      </Card>
    );
  }

  const CustomLabel = ({
    cx,
    cy,
    midAngle,
    innerRadius,
    outerRadius,
    percent,
  }: any) => {
    const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
    const x = cx + radius * Math.cos((-midAngle * Math.PI) / 180);
    const y = cy + radius * Math.sin((-midAngle * Math.PI) / 180);

    return (
      <text
        x={x}
        y={y}
        fill="white"
        textAnchor={x > cx ? "start" : "end"}
        dominantBaseline="central"
        className="font-bold text-sm"
      >
        {`${(percent * 100).toFixed(0)}%`}
      </text>
    );
  };

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center gap-2">
          <Briefcase className="w-5 h-5 text-blue-500" />
          <CardTitle>Work Mode Distribution</CardTitle>
        </div>
        <p className="text-sm text-muted-foreground">
          Breakdown of work arrangements
        </p>
      </CardHeader>
      <CardContent>
        <ResponsiveContainer width="100%" height={300}>
          <PieChart>
            <Pie
              data={data}
              cx="50%"
              cy="50%"
              labelLine={false}
              label={CustomLabel}
              outerRadius={100}
              fill="#8884d8"
              dataKey="value"
              animationBegin={0}
              animationDuration={800}
            >
              {data.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={entry.color} />
              ))}
            </Pie>
            <Tooltip content={<CustomTooltip />} />
            <Legend
              verticalAlign="bottom"
              height={36}
              formatter={(value) => <span className="text-sm">{value}</span>}
            />
          </PieChart>
        </ResponsiveContainer>
      </CardContent>
    </Card>
  );
}

"use client";

import { PolarAngleAxis, PolarGrid, Radar, RadarChart } from "recharts";
import {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
  type ChartConfig,
} from "@/components/ui/chart";

const chartConfig = {
  count: {
    label: "Jobs",
    color: "var(--chart-1)",
  },
} satisfies ChartConfig;

interface IndustryRadarClientProps {
  chartData: { industry: string; count: number }[];
}

// Custom tick component for wrapping text
const CustomTick = ({ payload, x, y, textAnchor, stroke }: any) => {
  const text = payload.value;
  const maxLength = 20;

  // Split long text into multiple lines
  const words = text.split(" ");
  const lines: string[] = [];
  let currentLine = "";

  words.forEach((word: string) => {
    const testLine = currentLine ? `${currentLine} ${word}` : word;
    if (testLine.length <= maxLength) {
      currentLine = testLine;
    } else {
      if (currentLine) lines.push(currentLine);
      currentLine = word;
    }
  });
  if (currentLine) lines.push(currentLine);

  // Calculate offset based on position to avoid dot overlap
  const isTop = y < 200;
  const isBottom = y > 300;
  const yOffset = isTop ? -8 : isBottom ? 8 : 0;

  return (
    <g>
      {lines.map((line, index) => (
        <text
          key={index}
          x={x}
          y={y + yOffset + index * 12 - (lines.length - 1) * 6}
          textAnchor={textAnchor}
          fill="var(--muted-foreground)"
          fontSize={11}
          fontWeight={500}
        >
          {line}
        </text>
      ))}
    </g>
  );
};

export function IndustryRadarClient({ chartData }: IndustryRadarClientProps) {
  return (
    <ChartContainer
      config={chartConfig}
      className="mx-auto aspect-square w-full max-w-[500px] h-[400px]"
    >
      <RadarChart
        data={chartData}
        margin={{ top: 50, right: 100, bottom: 50, left: 100 }}
      >
        <ChartTooltip
          cursor={false}
          content={
            <ChartTooltipContent
              labelFormatter={(value, payload) => {
                const fullName = payload?.[0]?.payload?.industry;
                return fullName || value;
              }}
            />
          }
        />
        <PolarAngleAxis dataKey="industry" tick={CustomTick} />
        <PolarGrid />
        <Radar
          dataKey="count"
          fill="var(--chart-1)"
          fillOpacity={0.6}
          dot={{
            r: 5,
            fillOpacity: 1,
          }}
        />
      </RadarChart>
    </ChartContainer>
  );
}

"use client";

import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Tooltip,
  Legend,
} from "recharts";

interface ExperienceData {
  level: string | null;
  count: number;
}

interface SharedExperienceChartProps {
  data: ExperienceData[];
  height?: number;
  showInnerRadius?: boolean;
}

const COLORS = ["#6366f1", "#8b5cf6", "#a855f7", "#c084fc", "#d8b4fe"];

const LEVEL_LABELS: Record<string, string> = {
  "Entry level": "Entry Level",
  "Mid-Senior level": "Mid Level",
  Associate: "Associate",
  Director: "Director",
  Executive: "Executive",
  Internship: "Internship",
  "Not Applicable": "Not Specified",
};

export function SharedExperienceChart({
  data,
  height = 350,
  showInnerRadius = true,
}: SharedExperienceChartProps) {
  const filteredData = data.filter((item) => item.level !== null);
  const total = filteredData.reduce((sum, item) => sum + item.count, 0);

  const formattedData = filteredData.map((item) => ({
    name: LEVEL_LABELS[item.level!] || item.level!,
    value: item.count,
    percentage: ((item.count / total) * 100).toFixed(1),
  }));

  return (
    <ResponsiveContainer width="100%" height={height}>
      <PieChart>
        <Pie
          data={formattedData}
          cx="50%"
          cy="45%"
          outerRadius={100}
          innerRadius={showInnerRadius ? 48 : 0}
          fill="#8884d8"
          dataKey="value"
        >
          {formattedData.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
          ))}
        </Pie>
        <Tooltip
          content={({ active, payload }) => {
            if (active && payload && payload.length) {
              const entry = payload[0];
              const value = entry?.value as number | undefined;
              const percentage = (entry?.payload as { percentage?: string })
                ?.percentage;
              return (
                <div className="rounded-lg border bg-background p-2 shadow-sm">
                  <div className="grid gap-2">
                    <div className="flex flex-col">
                      <span className="text-xs text-muted-foreground">
                        {entry.name}
                      </span>
                      <span className="font-bold">
                        {value?.toLocaleString() ?? 0} jobs ({percentage}%)
                      </span>
                    </div>
                  </div>
                </div>
              );
            }
            return null;
          }}
        />
        <Legend
          verticalAlign="bottom"
          height={80}
          formatter={(value, entry: any) => (
            <span className="text-sm">
              {value} — {entry.payload.percentage}% ({entry.payload.value.toLocaleString()})
            </span>
          )}
        />
      </PieChart>
    </ResponsiveContainer>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { CompanyCardWithCheckbox } from "./company-card-with-checkbox";
import { ComparisonPanel } from "./comparison-panel";

interface Company {
  company_id?: string;
  name: string;
  company_size: string;
  country: string;
  postings_count: number;
  slug: string;
}

interface ComparisonPanelWrapperProps {
  companies: Company[];
  offset: number;
}

const MAX_SELECTIONS = 5;

export function ComparisonPanelWrapper({
  companies,
  offset,
}: ComparisonPanelWrapperProps) {
  const [selectedCompanies, setSelectedCompanies] = useState<string[]>([]);
  const [comparisonData, setComparisonData] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Load comparison data when selections change
  useEffect(() => {
    async function loadComparisonData() {
      if (selectedCompanies.length > 0) {
        setIsLoading(true);
        try {
          const response = await fetch("/api/companies/compare", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({ companyIds: selectedCompanies }),
          });

          if (!response.ok) {
            throw new Error("Failed to fetch comparison data");
          }

          const data = await response.json();
          setComparisonData(data);
        } catch (error) {
          console.error("Failed to load comparison data:", error);
        } finally {
          setIsLoading(false);
        }
      } else {
        setComparisonData([]);
      }
    }

    loadComparisonData();
  }, [selectedCompanies]);

  const handleSelectionChange = (companyId: string, checked: boolean) => {
    setSelectedCompanies((prev) => {
      if (checked) {
        if (prev.length >= MAX_SELECTIONS) return prev;
        return [...prev, companyId];
      } else {
        return prev.filter((id) => id !== companyId);
      }
    });
  };

  const handleClearAll = () => {
    setSelectedCompanies([]);
  };

  const maxSelectionsReached = selectedCompanies.length >= MAX_SELECTIONS;

  return (
    <>
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">
        {companies.map((company: Company, index: number) => {
          const companyId = company.company_id || company.slug;
          const isSelected = selectedCompanies.includes(companyId);

          return (
            <div
              key={`${company.name}-${offset + index}`}
              className="relative group"
            >
              <Link href={`/companies/${company.slug}`} className="block">
                <div className="rounded-2xl border bg-card p-4 hover:shadow-lg transition-shadow h-full">
                  <CompanyCardWithCheckbox
                    name={company.name || "N/A"}
                    size={company.company_size}
                    country={company.country || "N/A"}
                    rank={offset + index + 1}
                    count={company.postings_count}
                    companyId={companyId}
                    isSelected={isSelected}
                    onSelectionChange={handleSelectionChange}
                    maxSelectionsReached={maxSelectionsReached}
                  />
                </div>
              </Link>
            </div>
          );
        })}
      </div>

      {/* Comparison Panel */}
      <ComparisonPanel
        selectedCompanies={selectedCompanies}
        companiesData={comparisonData}
        onClearAll={handleClearAll}
      />
    </>
  );
}

"use client";

import { useState } from "react";
import { X, GitCompare, Trash2 } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import {
  RadarChart,
  PolarGrid,
  PolarAngleAxis,
  PolarRadiusAxis,
  Radar,
  ResponsiveContainer,
  Legend,
  Tooltip,
} from "recharts";

interface CompanyData {
  company_id: string;
  name: string;
  location: string;
  company_size: string | null;
  posting_count: number;
  median_salary: number;
  avg_salary: number;
  industry_count: number;
}

interface ComparisonPanelProps {
  selectedCompanies: string[];
  companiesData: CompanyData[];
  onClearAll: () => void;
}

const COMPANY_COLORS = [
  "#3b82f6", // blue
  "#10b981", // emerald
  "#f59e0b", // amber
  "#8b5cf6", // purple
  "#ef4444", // red
];

function normalizeValue(value: number, max: number): number {
  return max > 0 ? (value / max) * 100 : 0;
}

export function ComparisonPanel({
  selectedCompanies,
  companiesData,
  onClearAll,
}: ComparisonPanelProps) {
  const [isOpen, setIsOpen] = useState(false);

  // Prepare radar chart data
  const maxValues = {
    posting_count: Math.max(...companiesData.map((c) => c.posting_count), 1),
    median_salary: Math.max(...companiesData.map((c) => c.median_salary ?? c.avg_salary), 1),
    industry_count: Math.max(...companiesData.map((c) => c.industry_count), 1),
  };

  const radarData = [
    {
      metric: "Postings",
      ...Object.fromEntries(
        companiesData.map((c, i) => [
          `company${i}`,
          normalizeValue(c.posting_count, maxValues.posting_count),
        ]),
      ),
    },
    {
      metric: "Median Salary",
      ...Object.fromEntries(
        companiesData.map((c, i) => [
          `company${i}`,
          normalizeValue(c.median_salary ?? c.avg_salary, maxValues.median_salary),
        ]),
      ),
    },
    {
      metric: "Industries",
      ...Object.fromEntries(
        companiesData.map((c, i) => [
          `company${i}`,
          normalizeValue(c.industry_count, maxValues.industry_count),
