                      {companiesData.map((company) => (
                        <td
                          key={company.company_id}
                          className="px-4 py-3 text-sm font-bold text-emerald-600 dark:text-emerald-400"
                        >
                          ${(company.median_salary ?? company.avg_salary).toLocaleString()}
