                      ))}
                    </tr>
                    <tr className="hover:bg-slate-50 dark:hover:bg-slate-900/50">
                      <td className="px-4 py-3 text-sm font-medium text-slate-700 dark:text-slate-300">
                        Industry Diversity
                      </td>
                      {companiesData.map((company) => (
                        <td
