                          {company.industry_count}{" "}
                          {company.industry_count === 1
                            ? "industry"
                            : "industries"}
                        </td>
                      ))}
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import * as React from "react";
import { useQueryStates } from "nuqs";
import { Search, X, SlidersHorizontal, RotateCcw } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { CategorySelect } from "./category-select";
import { RangeSlider } from "./range-slider";
import { ExperienceCheckboxGroup } from "./experience-checkbox-group";
import { SortDropdown } from "./sort-dropdown";
import { skillsSearchParamsParser } from "@/lib/skills-search-params";
import { useTransition } from "react";

export function FunctionalFilterBar() {
  const [searchParams, setSearchParams] = useQueryStates(
    skillsSearchParamsParser,
    {
      shallow: false,
    },
  );
  const [isPending, startTransition] = useTransition();
  const [isOpen, setIsOpen] = React.useState(false);
  const [searchInput, setSearchInput] = React.useState(searchParams.q);

  // Debounced search
  React.useEffect(() => {
    const timer = setTimeout(() => {
      if (searchInput !== searchParams.q) {
        startTransition(() => {
          setSearchParams({ q: searchInput, page: 1 });
        });
      }
    }, 300);

    return () => clearTimeout(timer);
  }, [searchInput, searchParams.q, setSearchParams]);

  // Count active filters
  const activeFiltersCount = React.useMemo(() => {
    let count = 0;
    if (searchParams.q) count++;
    if (searchParams.category.length > 0) count++;
    if (searchParams.demandMin > 0 || searchParams.demandMax < 10000) count++;
    if (searchParams.salaryMin > 40000 || searchParams.salaryMax < 200000)
      count++;
    if (searchParams.experience.length > 0) count++;
    if (searchParams.sort !== "demand") count++;
    return count;
  }, [searchParams]);

  const handleReset = () => {
    startTransition(() => {
      setSearchParams({
        q: "",
        category: [],
        demandMin: 0,
        demandMax: 10000,
        salaryMin: 40000,
        salaryMax: 200000,
        experience: [],
        sort: "demand",
        page: 1,
      });
      setSearchInput("");
    });
  };

  const formatSalary = (value: number) => {
    return `$${(value / 1000).toFixed(0)}k`;
  };

  const formatDemand = (value: number) => {
    return value >= 1000 ? `${(value / 1000).toFixed(1)}k` : value.toString();
  };

  return (
    <Card className="shadow-sm">
      <CardContent className="p-6">
        {/* Search Bar */}
        <div className="flex gap-2 mb-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
            <Input
              placeholder="Search skills (e.g., React, Python, AWS)..."
              value={searchInput}
              onChange={(e) => setSearchInput(e.target.value)}
              className="pl-9 pr-9"
            />
            {searchInput && (
              <button
                onClick={() => {
                  setSearchInput("");
                  startTransition(() => {
                    setSearchParams({ q: "", page: 1 });
                  });
                }}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                <X className="h-4 w-4" />
              </button>
            )}
          </div>
          <Button
            variant="outline"
            onClick={() => setIsOpen(!isOpen)}
            className="gap-2"
          >
            <SlidersHorizontal className="h-4 w-4" />
            Filters
            {activeFiltersCount > 0 && (
              <Badge variant="secondary" className="ml-1 rounded-full px-2">
                {activeFiltersCount}
              </Badge>
            )}
          </Button>
        </div>

        {/* Collapsible Filters */}
        <Collapsible open={isOpen} onOpenChange={setIsOpen}>
          <CollapsibleContent className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pt-4 border-t">
              {/* Category Filter */}
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
                  Categories
                </label>
                <CategorySelect
                  value={searchParams.category}
                  onChange={(category) =>
                    startTransition(() => {
                      setSearchParams({ category, page: 1 });
                    })
                  }
                />
              </div>

              {/* Sort Filter */}
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
                  Sort By
                </label>
                <SortDropdown
                  value={searchParams.sort}
                  onChange={(sort) =>
                    startTransition(() => {
                      setSearchParams({ sort, page: 1 });
                    })
                  }
                />
              </div>

              {/* Experience Level */}
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
                  Experience Level
                </label>
                <ExperienceCheckboxGroup
                  value={searchParams.experience}
                  onChange={(experience) =>
                    startTransition(() => {
                      setSearchParams({ experience, page: 1 });
                    })
                  }
                />
              </div>

              {/* Demand Range */}
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
                  Demand Level (Job Count)
                </label>
                <RangeSlider
                  min={0}
                  max={10000}
                  step={100}
                  value={[searchParams.demandMin, searchParams.demandMax]}
                  onChange={([demandMin, demandMax]) =>
                    startTransition(() => {
                      setSearchParams({ demandMin, demandMax, page: 1 });
                    })
                  }
                  formatLabel={formatDemand}
                />
              </div>

              {/* Salary Range */}
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
                  Salary Range
                </label>
                <RangeSlider
                  min={40000}
                  max={200000}
                  step={5000}
                  value={[searchParams.salaryMin, searchParams.salaryMax]}
                  onChange={([salaryMin, salaryMax]) =>
                    startTransition(() => {
                      setSearchParams({ salaryMin, salaryMax, page: 1 });
                    })
                  }
                  formatLabel={formatSalary}
                />
              </div>
            </div>

            {/* Filter Actions */}
            <div className="flex items-center justify-between pt-4 border-t">
              <Button
                variant="ghost"
                onClick={handleReset}
                className="gap-2"
                disabled={activeFiltersCount === 0}
              >
                <RotateCcw className="h-4 w-4" />
                Reset All Filters
              </Button>
              <div className="text-sm text-slate-500">
                {activeFiltersCount > 0 && (
                  <span>{activeFiltersCount} active filter(s)</span>
                )}
              </div>
            </div>
          </CollapsibleContent>
        </Collapsible>

        {/* Loading indicator */}
        {isPending && (
          <div className="mt-4 text-center text-sm text-slate-500">
            Applying filters...
          </div>
        )}
      </CardContent>
    </Card>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { useMap } from "react-leaflet";
import L from "leaflet";

interface HeatLayerProps {
  points: [number, number, number][];
  radius?: number;
  blur?: number;
  maxZoom?: number;
  max?: number;
  gradient?: Record<number, string>;
}

export default function HeatLayer({
  points,
  radius = 20,
  blur = 12,
  maxZoom = 18,
  max = 1.0,
  gradient,
}: HeatLayerProps) {
  const map = useMap();
  const heatLayerRef = useRef<any>(null);

  useEffect(() => {
    if (!map || points.length === 0) return;

    let cancelled = false;

    const init = async () => {
      // 🔑 CRITICAL: expose Leaflet BEFORE loading plugin
      (window as any).L = L;

      // side-effect import ONLY
      await import("leaflet.heat");

      if (cancelled) return;

      if (typeof (L as any).heatLayer !== "function") {
        throw new Error("leaflet.heat loaded but L.heatLayer is missing");
      }

      // cleanup previous
      if (heatLayerRef.current) {
        map.removeLayer(heatLayerRef.current);
        heatLayerRef.current = null;
      }

      // pane
      if (!map.getPane("heatmapPane")) {
        const pane = map.createPane("heatmapPane");
        pane.style.zIndex = "400";
      }

      heatLayerRef.current = (L as any)
        .heatLayer(points, {
          radius,
          blur,
          maxZoom,
          max,
          minOpacity: 0.3,
          pane: "heatmapPane",
          gradient: gradient ?? {
            0.0: "#0000ff",
            0.2: "#00ffff",
            0.4: "#00ff00",
            0.6: "#ffff00",
            0.8: "#ff8800",
            1.0: "#ff0000",
          },
        })
        .addTo(map);
    };

    init();

    return () => {
      cancelled = true;
      if (heatLayerRef.current) {
        map.removeLayer(heatLayerRef.current);
        heatLayerRef.current = null;
      }
    };
  }, [map, points, radius, blur, maxZoom, max, gradient]);

  return null;
}

"use client";

import { useEffect, useState } from "react";
import dynamic from "next/dynamic";

// Dynamically import map components
const MapContainer = dynamic(
  () => import("react-leaflet").then((mod) => mod.MapContainer),
  { ssr: false },
) as any;

const TileLayer = dynamic(
  () => import("react-leaflet").then((mod) => mod.TileLayer),
  { ssr: false },
) as any;

const CircleMarker = dynamic(
  () => import("react-leaflet").then((mod) => mod.CircleMarker),
  { ssr: false },
) as any;

const Popup = dynamic(() => import("react-leaflet").then((mod) => mod.Popup), {
  ssr: false,
}) as any;

// Import custom components
const HeatLayer = dynamic(() => import("./heat-layer"), { ssr: false }) as any;
import HeatLegend from "./heat-legend";
import MapControls from "./map-controls";

interface LocationData {
  city: string | null;
  state: string | null;
  country: string | null;
  lat: number | null;
  lng: number | null;
  jobCount: number;
  avgSalary: number | null;
  remoteRatio: number | null;
}

export default function LocationHeatMap({ data }: { data: LocationData[] }) {
  const [isMounted, setIsMounted] = useState(false);
  const [viewMode, setViewMode] = useState<"heat" | "markers" | "both">(
    "markers",
  );
  const [radius, setRadius] = useState(20); // Reduced from 25
  const [blur, setBlur] = useState(12); // Reduced from 15

  useEffect(() => {
    // Import Leaflet CSS dynamically
    if (typeof window !== "undefined") {
      const link = document.createElement("link");
      link.rel = "stylesheet";
      link.href = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.css";
      link.integrity = "sha256-p4NxAoJBhIIN+hmNHrzRCf9tD/miZyoHS5obTRR9BMY=";
      link.crossOrigin = "";
      document.head.appendChild(link);

      // Wait for CSS to load before mounting
      link.onload = () => {
        setIsMounted(true);
      };

      // Fallback in case onload doesn't fire
      setTimeout(() => setIsMounted(true), 500);
    }
  }, []);

  if (!isMounted) {
    return (
      <div className="h-150 bg-muted rounded-lg flex items-center justify-center">
        <p className="text-muted-foreground">Loading map...</p>
      </div>
    );
  }

  // Filter out locations without coordinates
  const validLocations = data.filter(
    (loc) => loc.lat !== null && loc.lng !== null && loc.city !== null,
  );

  if (validLocations.length === 0) {
    return (
      <div className="h-150 bg-muted rounded-lg flex items-center justify-center">
        <p className="text-muted-foreground">No location data available</p>
      </div>
    );
  }

  const maxJobs = Math.max(...validLocations.map((d) => d.jobCount));
  const minJobs = Math.min(...validLocations.map((d) => d.jobCount));

  // Prepare heat map points: [lat, lng, intensity]
  const heatPoints: [number, number, number][] = validLocations.map((loc) => [
    loc.lat!,
    loc.lng!,
    loc.jobCount / maxJobs, // Normalize intensity 0-1
  ]);

  return (
    <div className="h-150 rounded-lg overflow-hidden border relative">
      <MapContainer
        center={[20, 0]}
        zoom={2}
        style={{ height: "100%", width: "100%" }}
        scrollWheelZoom={true}
        className="z-0"
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        {/* Heat Layer */}
        {(viewMode === "heat" || viewMode === "both") && (
          <HeatLayer
            points={heatPoints}
            radius={radius}
            blur={blur}
            max={1.0}
          />
        )}

        {/* Circle Markers */}
        {(viewMode === "markers" || viewMode === "both") &&
          validLocations.map((location, idx) => {
            // Scale radius based on job count
            const markerRadius =
              Math.sqrt(location.jobCount / maxJobs) * 40 + 5;

            // Color based on job count intensity
            const intensity = location.jobCount / maxJobs;
            const color = `hsl(${200 - intensity * 100}, 70%, 50%)`;

            return (
              <CircleMarker
                key={idx}
                center={[location.lat!, location.lng!]}
                radius={markerRadius}
                pathOptions={{
                  fillColor: color,
                  color: "#1e40af",
                  weight: 1,
                  opacity: 0.8,
                  fillOpacity: viewMode === "both" ? 0.3 : 0.6,
                }}
              >
                <Popup>
                  <div className="min-w-50">
                    <h3 className="font-bold text-base mb-2">
                      {location.city}
                      {location.state &&
                        location.state !== "0" &&
                        `, ${location.state}`}
                      {location.country && ` (${location.country})`}
                    </h3>
                    <div className="space-y-1 text-sm">
                      <p>
                        <span className="font-semibold">Jobs:</span>{" "}
                        {location.jobCount.toLocaleString()}
                      </p>
                      {location.avgSalary && (
                        <p>
                          <span className="font-semibold">Median Salary:</span> $
                          {Math.round(location.avgSalary).toLocaleString()}
                        </p>
                      )}
                      {location.remoteRatio !== null && (
                        <p>
                          <span className="font-semibold">Remote:</span>{" "}
                          {Math.round(location.remoteRatio * 100)}%
                        </p>
                      )}
                    </div>
                    <a
                      href={`/locations/${location.city?.toLowerCase().replace(/[^a-z0-9]+/g, "-")}`}
                      className="text-blue-600 hover:underline text-sm mt-2 inline-block"
                    >
                      View details &rarr;
                    </a>
                  </div>
                </Popup>
              </CircleMarker>
            );
          })}
      </MapContainer>

      {/* Controls */}
      <MapControls
        viewMode={viewMode}
        onViewModeChange={setViewMode}
        radius={radius}
        onRadiusChange={setRadius}
        blur={blur}
        onBlurChange={setBlur}
      />

      {/* Legend (only show in heat mode) */}
      {(viewMode === "heat" || viewMode === "both") && (
        <HeatLegend min={minJobs} max={maxJobs} label="Job Postings" />
      )}
    </div>
  );
}

import { Suspense } from "react";
import LocationHeatMap from "@/components/ui/heatmap/location-heat-map";
