"use client";

import { m, Variants } from "framer-motion";
import { ReactNode } from "react";
import { cn } from "@/lib/utils";

// Stagger container for grid items
const containerVariants: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05,
      delayChildren: 0.1,
    },
  },
};

// Individual item animation
const itemVariants: Variants = {
  hidden: {
    opacity: 0,
    y: 20,
    scale: 0.95,
  },
  visible: {
    opacity: 1,
    y: 0,
    scale: 1,
    transition: {
      type: "spring",
      stiffness: 300,
      damping: 24,
    },
  },
};

interface MotionGridProps {
  children: ReactNode;
  className?: string;
}

/**
 * Animated grid container with staggered children
 */
export function MotionGrid({ children, className }: MotionGridProps) {
  return (
    <m.div
      variants={containerVariants}
      initial="hidden"
      animate="visible"
      className={cn("bento-grid", className)}
    >
      {children}
    </m.div>
  );
}

interface MotionItemProps {
  children: ReactNode;
  className?: string;
}

/**
 * Animated grid item with entrance animation
 */
export function MotionItem({ children, className }: MotionItemProps) {
  return (
    <m.div variants={itemVariants} className={className}>
      {children}
    </m.div>
  );
}

// Fade in animation for sections
const fadeInVariants: Variants = {
  hidden: { opacity: 0, y: 10 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.4, ease: "easeOut" },
  },
};

interface MotionFadeProps {
  children: ReactNode;
  className?: string;
  delay?: number;
}

/**
 * Simple fade-in animation wrapper
 */
export function MotionFade({
  children,
  className,
  delay = 0,
}: MotionFadeProps) {
  return (
    <m.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, ease: "easeOut", delay }}
      className={className}
    >
      {children}
    </m.div>
  );
}

// List stagger for leaderboards
const listContainerVariants: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.03,
    },
  },
};

const listItemVariants: Variants = {
  hidden: { opacity: 0, x: -10 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.2 },
  },
};

interface MotionListProps {
  children: ReactNode;
  className?: string;
}

/**
 * Animated list container for leaderboards
 */
export function MotionList({ children, className }: MotionListProps) {
  return (
    <m.ul
      variants={listContainerVariants}
      initial="hidden"
      animate="visible"
      className={className}
    >
      {children}
    </m.ul>
  );
}

export function MotionListItem({ children, className }: MotionItemProps) {
  return (
    <m.li variants={listItemVariants} className={className}>
      {children}
    </m.li>
  );
}

"use client";

import * as React from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  ScatterChart,
  Scatter,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell,
  ZAxis,
} from "recharts";
import { useRouter } from "next/navigation";

interface SkillDataPoint {
  name: string;
  demand: number;
  salary: number;
  growth?: number;
  category?: string;
}

interface DemandSalaryScatterProps {
  data: SkillDataPoint[];
}

const CATEGORY_COLORS: Record<string, string> = {
  "Programming Languages": "#3b82f6",
  "Frameworks & Libraries": "#10b981",
  "Databases & Data": "#8b5cf6",
  "DevOps & Cloud": "#f59e0b",
  "Tools & Platforms": "#ef4444",
  "AI/ML & Data Science": "#ec4899",
  "Soft Skills": "#06b6d4",
  default: "#64748b",
};

export function DemandSalaryScatter({ data }: DemandSalaryScatterProps) {
  const router = useRouter();

  const processedData = data.map((item) => ({
    ...item,
    x: item.demand,
    y: item.salary,
    z: item.growth || 10,
    fill: CATEGORY_COLORS[item.category || ""] || CATEGORY_COLORS.default,
  }));

  // Calculate quadrant lines
  const avgDemand =
    data.reduce((sum, item) => sum + item.demand, 0) / data.length;
  const avgSalary =
    data.reduce((sum, item) => sum + item.salary, 0) / data.length;

  const handleClick = (data: any) => {
    if (data && data.name) {
      router.push(`/skills/${encodeURIComponent(data.name.toLowerCase())}`);
    }
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle>Demand vs Salary Analysis</CardTitle>
        <p className="text-sm text-slate-500 dark:text-slate-400">
          Explore the relationship between skill demand and median salary.
          Bubble size indicates growth rate.
        </p>
      </CardHeader>
      <CardContent>
        <div className="h-[500px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ScatterChart margin={{ top: 20, right: 20, bottom: 60, left: 60 }}>
              <CartesianGrid
                strokeDasharray="3 3"
                className="stroke-slate-200 dark:stroke-slate-800"
              />
              <XAxis
                type="number"
                dataKey="x"
                name="Demand"
                label={{
                  value: "Job Postings (Demand)",
                  position: "bottom",
                  offset: 40,
                  style: { fill: "currentColor" },
                }}
                className="text-xs"
                tick={{ fill: "currentColor" }}
              />
              <YAxis
                type="number"
                dataKey="y"
                name="Salary"
                label={{
                  value: "Median Salary ($)",
                  angle: -90,
                  position: "left",
                  offset: 40,
                  style: { fill: "currentColor" },
                }}
                className="text-xs"
                tick={{ fill: "currentColor" }}
              />
              <ZAxis type="number" dataKey="z" range={[50, 400]} />
              <Tooltip
                cursor={{ strokeDasharray: "3 3" }}
                content={({ active, payload }) => {
                  if (active && payload && payload.length) {
                    const data = payload[0].payload;
                    return (
                      <div className="rounded-lg border bg-white dark:bg-slate-950 p-3 shadow-md">
                        <p className="font-semibold text-sm mb-2">
                          {data.name}
                        </p>
                        <p className="text-xs text-slate-600 dark:text-slate-400">
                          Demand: {data.demand.toLocaleString()} jobs
                        </p>
                        <p className="text-xs text-slate-600 dark:text-slate-400">
                          Salary: ${(data.salary / 1000).toFixed(0)}k
                        </p>
                        {data.growth && (
                          <p className="text-xs text-slate-600 dark:text-slate-400">
                            Growth: {data.growth.toFixed(1)}%
                          </p>
                        )}
                        {data.category && (
                          <p className="text-xs text-slate-600 dark:text-slate-400 mt-1">
                            {data.category}
                          </p>
                        )}
                      </div>
                    );
                  }
                  return null;
                }}
              />
              <Scatter
                data={processedData}
                onClick={handleClick}
                className="cursor-pointer"
              >
                {processedData.map((entry, index) => (
                  <Cell
                    key={`cell-${index}`}
                    fill={entry.fill}
                    fillOpacity={0.8}
                  />
                ))}
              </Scatter>

              {/* Quadrant labels */}
              <text
                x="85%"
                y="15%"
                textAnchor="middle"
                className="text-xs font-medium fill-green-600 dark:fill-green-400"
              >
                High Demand
                <tspan x="85%" dy="1.2em">
                  High Salary
                </tspan>
              </text>
              <text
                x="15%"
                y="15%"
                textAnchor="middle"
                className="text-xs font-medium fill-blue-600 dark:fill-blue-400"
              >
                Low Demand
                <tspan x="15%" dy="1.2em">
                  High Salary
                </tspan>
              </text>
              <text
                x="85%"
                y="85%"
                textAnchor="middle"
                className="text-xs font-medium fill-orange-600 dark:fill-orange-400"
              >
                High Demand
                <tspan x="85%" dy="1.2em">
                  Low Salary
                </tspan>
              </text>
              <text
                x="15%"
                y="85%"
                textAnchor="middle"
                className="text-xs font-medium fill-slate-600 dark:fill-slate-400"
              >
                Low Demand
                <tspan x="15%" dy="1.2em">
                  Low Salary
                </tspan>
              </text>
            </ScatterChart>
          </ResponsiveContainer>
        </div>

        {/* Legend */}
        <div className="mt-4 flex flex-wrap gap-4 justify-center">
          {Object.entries(CATEGORY_COLORS)
            .filter(([key]) => key !== "default")
            .map(([category, color]) => (
              <div key={category} className="flex items-center gap-2">
                <div
                  className="w-3 h-3 rounded-full"
                  style={{ backgroundColor: color }}
                />
                <span className="text-xs text-slate-600 dark:text-slate-400">
                  {category}
                </span>
              </div>
            ))}
        </div>
      </CardContent>
    </Card>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { Download, Share2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface SkillExportData {
  name: string;
  count: number;
  median_salary: number;
  category?: string;
  growth?: number;
}

interface ExportActionsProps {
  data: SkillExportData[];
  filters?: Record<string, any>;
}

export function ExportActions({ data, filters }: ExportActionsProps) {
  const { toast } = useToast();

  const exportToCSV = () => {
    try {
      const headers = ["Skill", "Category", "Demand", "Median Salary", "Growth %"];

      const rows = data.map((skill) => [
        skill.name,
        skill.category || "N/A",
        skill.count,
        skill.median_salary,
        skill.growth || "N/A",
      ]);

      const csv = [headers, ...rows]
        .map((row) => row.map((cell) => `"${cell}"`).join(","))
        .join("\n");

      const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `skills-export-${new Date().toISOString().split("T")[0]}.csv`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

      toast({
        title: "Export Successful",
        description: `Exported ${data.length} skills to CSV`,
      });
    } catch (error) {
      toast({
        title: "Export Failed",
        description: "There was an error exporting the data",
        variant: "destructive",
      });
    }
  };

  const shareFilters = () => {
    const url = window.location.href;
    navigator.clipboard.writeText(url).then(
      () => {
        toast({
          title: "Link Copied",
          description: "Current filter URL copied to clipboard",
        });
      },
      () => {
        toast({
          title: "Copy Failed",
          description: "Failed to copy URL to clipboard",
          variant: "destructive",
        });
      },
    );
  };

  return (
    <div className="flex gap-2">
      <Button variant="outline" className="gap-2" onClick={shareFilters}>
        <Share2 className="h-4 w-4" />
        Share Filters
      </Button>
      <Button className="gap-2 shadow-sm" onClick={exportToCSV}>
        <Download className="h-4 w-4" />
        Export Data
      </Button>
    </div>
  );
}

import { ArrowUp, ArrowDown, ArrowRight } from "lucide-react";
