// Salary benchmark by role
// ===========================
export async function getRolesSalaryBenchmark(limit = 15) {
  const result = await db.execute<{
    title: string;
    median_salary: number;
    avg_salary: number;
    posting_count: number;
    salary_coverage: number;
  }>(sql`
    WITH role_totals AS (
      SELECT
        COALESCE(ra.canonical_name, p.title) AS title,
        COUNT(*)::int AS total_count
      FROM ${postings} p
      LEFT JOIN ${roleAliases} ra ON LOWER(p.title) = LOWER(ra.alias)
      GROUP BY COALESCE(ra.canonical_name, p.title)
    ),
    role_salary AS (
      SELECT
        COALESCE(ra.canonical_name, p.title) AS title,
        ROUND(PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY p.yearly_min_salary))::int AS median_salary,
        COUNT(*)::int AS salary_count
      FROM ${postings} p
      LEFT JOIN ${roleAliases} ra ON LOWER(p.title) = LOWER(ra.alias)
      WHERE ${validAnnualSalaryFilter("p")}
      GROUP BY COALESCE(ra.canonical_name, p.title)
      HAVING COUNT(*) >= 10
    )
    SELECT
      rs.title,
      rs.median_salary,
      rs.median_salary AS avg_salary,
      rt.total_count AS posting_count,
      ROUND(rs.salary_count::numeric / rt.total_count * 100)::int AS salary_coverage
    FROM role_salary rs
    JOIN role_totals rt ON rs.title = rt.title
    ORDER BY rs.median_salary DESC
    LIMIT ${limit}
  `);

  return result.rows.map(row => ({
    title: row.title,
    median_salary: Number(row.median_salary),
    avg_salary: Number(row.avg_salary),
    posting_count: Number(row.posting_count),
    salary_coverage: Number(row.salary_coverage),
  }));
}

"use client"

import * as React from "react"

import type { ToastActionElement, ToastProps } from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

// lib/adzuna-import-helpers.ts
import { createHash } from 'crypto';
import { eq, and, sql } from 'drizzle-orm';
import { db } from '@/db';
import { postings, companies, job_skills, job_industries, industries } from '@/db/schema';
import type { AdzunaJob } from './adzuna/types';
import { matchSkills } from './adzuna/utils';
import { normalizeAnnualSalary } from './salary-normalization';

/**
 * Rate limiter class to respect Adzuna API limits:
 * - 25 requests per minute
 * - 250 requests per day
 * - 1,000 requests per week
 * - 2,500 requests per month
 */
export class AdzunaRateLimiter {
  private requestCount = 0;
  private dailyLimit: number;
  private delayMs: number;
  private lastRequestTime = 0;

  constructor(
    dailyLimit = 240, // Leave 10 request buffer under 250/day limit
    delayMs = 2500    // 2.5 seconds between requests (24 req/min, safely under 25/min)
  ) {
    this.dailyLimit = dailyLimit;
    this.delayMs = delayMs;
  }

  async waitForNextRequest(): Promise<void> {
    if (this.requestCount >= this.dailyLimit) {
      throw new Error(
        `Daily API limit reached (${this.requestCount}/${this.dailyLimit} requests). Please try again tomorrow.`
      );
    }

    const now = Date.now();
    const timeSinceLastRequest = now - this.lastRequestTime;

    if (timeSinceLastRequest < this.delayMs) {
      const waitTime = this.delayMs - timeSinceLastRequest;
      await new Promise(resolve => setTimeout(resolve, waitTime));
    }

    this.lastRequestTime = Date.now();
    this.requestCount++;
  }

  getRequestCount(): number {
    return this.requestCount;
  }

  getRemainingRequests(): number {
    return this.dailyLimit - this.requestCount;
  }

  getUsageStats(): { used: number; limit: number; remaining: number } {
    return {
      used: this.requestCount,
      limit: this.dailyLimit,
      remaining: this.getRemainingRequests(),
    };
  }
}

/**
 * Normalize company name for matching and ID generation
 * Removes common suffixes, extra whitespace, and special characters
 * Handles generic names like "Anonymous" and "Confidential"
 */
export function normalizeCompanyName(companyName: string, locationForGeneric?: string): string {
  if (!companyName || companyName.trim() === '') {
    return 'unknown';
  }

  let normalized = companyName
    .toLowerCase()
    .trim()
    // Remove common business suffixes
    .replace(/\s+(inc\.?|llc\.?|corp\.?|corporation\.?|ltd\.?|limited\.?|co\.?|company)$/i, '')
    // Remove extra whitespace
    .replace(/\s+/g, ' ')
    // Remove special characters but keep spaces and hyphens
    .replace(/[^a-z0-9\s-]/g, '')
    .trim();

  // Handle generic/anonymous company names
  const genericNames = ['anonymous', 'confidential', 'confidential company', 'undisclosed'];
  if (genericNames.includes(normalized)) {
    // Make generic names unique by appending location
    if (locationForGeneric) {
      const locationNormalized = locationForGeneric.toLowerCase().replace(/[^a-z0-9]/g, '');
      normalized = `${normalized}-${locationNormalized}`;
    }
  }

  return normalized || 'unknown';
}

/**
 * Generate a deterministic company ID from company name only.
 * Uses SHA-256 hash of the normalized name.
 * 
 * DESIGN TRADE-OFF (portfolio/demo project):
 * Name-only hashing means "ABC Construction" in TX and CA would share one record.
 * This is acceptable for a demo project because:
 * - National companies (Jobot, MAXIMUS, Boeing) are clearly the same entity
 * - The alternative (name+location) created 1,465+ duplicate records
 * - For a production system, consider name+state or a company registry lookup
 * 
 * @param companyName - Raw company name from job posting
 * @returns 16-character hex hash
 */
export function generateCompanyId(companyName: string): string {
  const normalized = normalizeCompanyName(companyName);
  return createHash('sha256').update(normalized).digest('hex').substring(0, 16);
}

/**
 * Parse location string to extract city and state
 * Examples: "San Francisco, CA" -> { city: "San Francisco", state: "CA" }
 */
export function parseLocation(locationDisplay: string): {
  city: string | null;
  state: string | null;
  country: string;
} {
  const parts = locationDisplay.split(',').map(p => p.trim());
  
  if (parts.length >= 2) {
    const state = parts[parts.length - 1];
    const city = parts[parts.length - 2];
    return { city, state, country: 'United States' };
  }
  
  return { city: parts[0] || null, state: null, country: 'United States' };
}

/**
 * Transform Adzuna job to our database schema
 * 
 * UPDATED: Now includes country field for global job deduplication
 * Company ID now uses parsed city+state instead of full location string
 */
export function transformAdzunaJob(job: AdzunaJob, country: string = 'US'): {
  job_id: string;
  external_id: string;
  source: string;
  country: string;
  company_name: string;
  company_id: string;
  title: string;
  description: string | null;
  skills_desc: string | null;
  location: string;
  min_salary: number | null;
  max_salary: number | null;
  yearly_min_salary: number | null;
  yearly_max_salary: number | null;
  med_salary: number | null;
  yearly_med_salary: number | null;
  pay_period: string;
  currency: string;
  compensation_type: string;
  job_posting_url: string;
  application_url: string;
  listed_time: Date;
  original_listed_time: Date;
  work_type: string | null;
  formatted_work_type: string | null;
  remote_allowed: boolean;
  sponsored: boolean;
  import_timestamp: Date;
} {
  const companyName = job.company.display_name;
  const locationDisplay = job.location.display_name;
  
  // Parse location to extract city and state
  const location = parseLocation(locationDisplay);
  
  // Generate company ID (name-only, no location)
  const companyId = generateCompanyId(companyName);
  
  // Adzuna salaries are typically annual.
  const minSalary = job.salary_min ?? null;
  const maxSalary = job.salary_max ?? null;
  const normalizedSalary = normalizeAnnualSalary(minSalary, maxSalary, 'YEARLY', 'adzuna');

  if (normalizedSalary.rejected) {
    console.warn(
      '[salary_rejected]',
      JSON.stringify({
        source: 'adzuna',
        external_id: job.id,
        job_id: `adzuna_${job.id}`,
        reason: normalizedSalary.rejectionReason,
        min_salary: minSalary,
        max_salary: maxSalary,
        pay_period: 'YEARLY',
      })
    );
  }
  
  // Generate a unique job_id from external_id and source
  const jobId = `adzuna_${job.id}`;
  
  return {
    job_id: jobId,
    external_id: job.id,
    source: 'adzuna',
    country, // Required for global deduplication
    company_name: companyName,
    company_id: companyId,
    title: job.title,
    description: job.description || null,
    skills_desc: job.description || null, // Store raw description for future re-processing
    location: job.location.display_name,
    min_salary: minSalary,
    max_salary: maxSalary,
    yearly_min_salary: normalizedSalary.minAnnual,
    yearly_max_salary: normalizedSalary.maxAnnual,
    med_salary: normalizedSalary.medAnnual,
    yearly_med_salary: normalizedSalary.medAnnual,
    pay_period: 'YEARLY',
    currency: 'USD',
    compensation_type: 'salary',
    job_posting_url: job.redirect_url,
    application_url: job.redirect_url,
    listed_time: new Date(job.created),
    original_listed_time: new Date(job.created),
    work_type: job.contract_type ?? null,
    formatted_work_type: job.contract_type ?? null,
    remote_allowed: job.location.display_name.toLowerCase().includes('remote'),
    sponsored: false,
    import_timestamp: new Date(),
  };
}

/**
 * Find existing company by company_id or create a new one.
 * Returns the company_id.
 * 
 * Company ID is derived from name only (no location). This means the same
 * company posting from multiple cities shares one record. Location stored
 * on the record is from the first job seen (not updated on subsequent matches).
 */
export async function findOrCreateCompany(
  companyName: string,
  locationDisplay: string,
  lat?: number | null,
  lng?: number | null
): Promise<string> {
  // Validate input
  if (!companyName || companyName.trim() === '') {
    console.warn('⚠️  Empty company name provided, using "Unknown Company"');
    companyName = 'Unknown Company';
  }

  // Parse location to extract city and state
  const location = parseLocation(locationDisplay);
  
  // Generate deterministic company ID (name-only for demo simplicity)
  const companyId = generateCompanyId(companyName);
  const normalizedName = normalizeCompanyName(companyName, locationDisplay);
  
  // STEP 1: Check if company exists by company_id (PRIMARY KEY lookup - fastest)
  const existingById = await db
    .select({ 
      company_id: companies.company_id,
      name: companies.name 
    })
    .from(companies)
    .where(eq(companies.company_id, companyId))
    .limit(1);

  if (existingById.length > 0) {
    // Company found by ID — update lat/lng if currently null and we have values
    if (lat != null && lng != null) {
      const existing = await db
        .select({ lat: companies.lat, lng: companies.lng })
        .from(companies)
        .where(eq(companies.company_id, companyId))
        .limit(1);
      
      if (existing.length > 0 && existing[0].lat == null && existing[0].lng == null) {
        await db.update(companies)
          .set({ lat, lng })
          .where(eq(companies.company_id, companyId));
      }
    }
    return existingById[0].company_id;
  }

  // STEP 2: Company doesn't exist - create it
  try {
    await db.insert(companies).values({
      company_id: companyId,
      name: companyName,
      city: location.city,
      state: location.state,
      country: location.country,
      description: null,
      company_size: null,
      zip_code: null,
      address: null,
      url: null,
      lat: lat ?? null,
      lng: lng ?? null,
    });
    
    console.log(`✅ Created new company: ${companyName} (${location.city}, ${location.state}) → ${companyId}`);
    return companyId;
    
  } catch (error: any) {
    // Handle duplicate key violation (PostgreSQL error code 23505)
    if (error.code === '23505' || error.message.includes('duplicate key')) {
      console.log(`ℹ️  Company already exists (caught via conflict): ${companyName} (${companyId})`);
      
      // Retry the SELECT to get the existing company_id
      const retry = await db
        .select({ company_id: companies.company_id })
        .from(companies)
        .where(eq(companies.company_id, companyId))
        .limit(1);
      
      if (retry.length > 0) {
        return retry[0].company_id;
      }
      
      // If still not found, something is wrong
      console.error(`❌ Failed to find company after conflict: ${companyName}`);
      throw new Error(`Company conflict but cannot retrieve: ${companyName}`);
    }
    
    // Re-throw other errors
    console.error(`❌ Error creating company ${companyName}:`, error.message);
    throw error;
  }
}

/**
 * Check if a job already exists in the database
 * UPDATED: Now checks by (external_id, source, country) for global uniqueness
 */
export async function jobExists(
  externalId: string,
  source: string,
  country: string
): Promise<boolean> {
  const result = await db
    .select({ job_id: postings.job_id })
    .from(postings)
    .where(
      and(
        eq(postings.external_id, externalId),
        eq(postings.source, source),
        eq(postings.country, country)
      )
    )
    .limit(1);

  return result.length > 0;
}

/**
 * Batch insert jobs with conflict handling
 * Uses (external_id, source, country) for deduplication
 * UPDATED: Now includes country field for global uniqueness
 */
export async function batchInsertJobs(
  jobs: Awaited<ReturnType<typeof transformAdzunaJob>>[]
): Promise<{ inserted: number; updated: number; failed: number }> {
  if (jobs.length === 0) return { inserted: 0, updated: 0, failed: 0 };

  try {
    await db
      .insert(postings)
      .values(jobs)
      .onConflictDoUpdate({
        target: [postings.external_id, postings.source, postings.country],
        set: {
          title: sql`excluded.title`,
          description: sql`excluded.description`,
          min_salary: sql`excluded.min_salary`,
          max_salary: sql`excluded.max_salary`,
          yearly_min_salary: sql`excluded.yearly_min_salary`,
          yearly_max_salary: sql`excluded.yearly_max_salary`,
          med_salary: sql`excluded.med_salary`,
          yearly_med_salary: sql`excluded.yearly_med_salary`,
          location: sql`excluded.location`,
          work_type: sql`excluded.work_type`,
          formatted_work_type: sql`excluded.formatted_work_type`,
          remote_allowed: sql`excluded.remote_allowed`,
          country: sql`excluded.country`,
          import_timestamp: sql`excluded.import_timestamp`,
        },
      });
    return { inserted: jobs.length, updated: 0, failed: 0 };
  } catch (error: any) {
    console.error(`❌ Batch upsert failed:`, error.message);
    return { inserted: 0, updated: 0, failed: jobs.length };
  }
}

/**
 * Validation function to check data quality
 */
export function validateJobData(job: AdzunaJob): {
  isValid: boolean;
  warnings: string[];
} {
  const warnings: string[] = [];

  if (!job.id) {
    warnings.push('Missing job ID');
  }

  if (!job.title || job.title.trim() === '') {
    warnings.push('Missing or empty title');
  }

  if (!job.company?.display_name) {
    warnings.push('Missing company name');
  }

  if (!job.location?.display_name) {
    warnings.push('Missing location');
  }

  if (!job.description || job.description.trim() === '') {
    warnings.push('Missing or empty description');
  }

  if (!job.redirect_url) {
    warnings.push('Missing redirect URL');
  }

  if (!job.created) {
    warnings.push('Missing created date');
  }

  const isValid = warnings.length === 0;
  return { isValid, warnings };
}

/**
 * Extract skills from job titles and descriptions, then insert into job_skills.
 * Uses the SKILL_KEYWORDS dictionary from lib/adzuna/utils.ts.
 */
export async function extractAndInsertSkills(
  jobs: { job_id: string; title: string; description: string | null }[]
): Promise<{ inserted: number; skipped: number }> {
  let inserted = 0;
  let skipped = 0;

  // Load valid skill_abrs from the database
  const dbSkills = await db.execute(sql`SELECT skill_abr FROM skills`);
  const validAbrs = new Set(dbSkills.rows.map((r: any) => r.skill_abr));

  // Collect all (job_id, skill_abr) pairs
  const allPairs: { job_id: string; skill_abr: string }[] = [];

  for (const job of jobs) {
    const matched = matchSkills(job.title, job.description || '');
    for (const skillAbr of matched) {
      if (validAbrs.has(skillAbr)) {
        allPairs.push({ job_id: job.job_id, skill_abr: skillAbr });
      }
    }
  }

  if (allPairs.length === 0) {
    return { inserted: 0, skipped: 0 };
  }

  // Batch insert with ON CONFLICT DO NOTHING
  const BATCH_SIZE = 500;
  for (let i = 0; i < allPairs.length; i += BATCH_SIZE) {
    const batch = allPairs.slice(i, i + BATCH_SIZE);
    const valuesClauses = batch.map(
      p => sql`(${p.job_id}, ${p.skill_abr})`
    );

    try {
      const result = await db.execute(sql`
        INSERT INTO job_skills (job_id, skill_abr)
        VALUES ${sql.join(valuesClauses, sql`, `)}
        ON CONFLICT DO NOTHING
      `);
      const batchInserted = Number(result.rowCount ?? batch.length);
      inserted += batchInserted;
      skipped += batch.length - batchInserted;
    } catch (error: any) {
      console.error(`   ❌ Skill insert batch error:`, error.message);
      skipped += batch.length;
    }
  }

  return { inserted, skipped };
}

/**
 * Map Adzuna category to industry and insert into job_industries.
 * Creates new industry record if category tag doesn't exist yet.
 */
export async function mapCategoryToIndustry(
  jobId: string,
  categoryTag: string,
  categoryLabel: string
): Promise<void> {
  if (!categoryTag || !categoryLabel) return;

  try {
    // Check if industry exists
    const existing = await db.execute(
      sql`SELECT industry_id FROM industries WHERE industry_id = ${categoryTag} LIMIT 1`
    );

    if (existing.rows.length === 0) {
      // Create new industry
      await db.execute(
        sql`INSERT INTO industries (industry_id, industry_name) VALUES (${categoryTag}, ${categoryLabel}) ON CONFLICT DO NOTHING`
      );
    }

    // Insert job_industries mapping
    await db.execute(
      sql`INSERT INTO job_industries (job_id, industry_id) VALUES (${jobId}, ${categoryTag}) ON CONFLICT DO NOTHING`
    );
  } catch (error: any) {
    // Silently skip conflicts
    if (!error.message.includes('duplicate key')) {
      console.error(`   ⚠️  Industry mapping error for ${jobId}:`, error.message);
    }
  }
}

// lib/adzuna-usage-tracker.ts
/**
 * Database-backed API usage tracker for Adzuna API quotas
 * 
 * Replaces file-based .adzuna-usage.json with PostgreSQL persistence
 * Provides transactional safety for CI/CD environments where multiple
 * runs could race on file access.
 * 
 * Quotas:
 * - 25 requests per minute (handled by rate limiter)
 * - 250 requests per day
 * - 1,000 requests per week  
 * - 2,500 requests per month
 */

import { db } from '@/db';
import { adzunaUsage } from '@/db/schema';
import { eq, and, sql } from 'drizzle-orm';

export type PeriodType = 'daily' | 'weekly' | 'monthly';

interface UsageRecord {
  period: PeriodType;
  periodKey: string;
  requestCount: number;
}

/**
 * Get the period key for a given date and period type
 * 
 * - daily: '2026-02-15'
 * - weekly: '2026-W07' (ISO week number)
 * - monthly: '2026-02'
 */
function getPeriodKey(date: Date, period: PeriodType): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');

  switch (period) {
    case 'daily':
      return `${year}-${month}-${day}`;
    
    case 'weekly': {
      // ISO week number calculation
      const temp = new Date(date.getTime());
      temp.setDate(temp.getDate() + 3 - ((temp.getDay() + 6) % 7));
      const week = Math.ceil(((temp.getTime() - new Date(temp.getFullYear(), 0, 4).getTime()) / 86400000 + 1) / 7);
      return `${temp.getFullYear()}-W${String(week).padStart(2, '0')}`;
    }
    
    case 'monthly':
      return `${year}-${month}`;
    
    default:
      throw new Error(`Unknown period type: ${period}`);
  }
}

/**
 * Get current usage for a specific period
 * Returns 0 if no record exists
 */
export async function getUsage(period: PeriodType, date: Date = new Date()): Promise<number> {
  const periodKey = getPeriodKey(date, period);

  const [record] = await db
    .select({ request_count: adzunaUsage.request_count })
    .from(adzunaUsage)
    .where(
      and(
        eq(adzunaUsage.period, period),
        eq(adzunaUsage.period_key, periodKey)
      )
    )
    .limit(1);

  return record?.request_count ?? 0;
}

/**
 * Get usage for all periods (daily, weekly, monthly)
 * Returns a map of period -> count
 */
export async function getAllUsage(date: Date = new Date()): Promise<Record<PeriodType, number>> {
  const periods: PeriodType[] = ['daily', 'weekly', 'monthly'];
  const results = await Promise.all(
    periods.map(async (period) => {
      const count = await getUsage(period, date);
      return [period, count] as const;
    })
  );

  return Object.fromEntries(results) as Record<PeriodType, number>;
}

/**
 * Increment usage count for a given period
 * Creates record if it doesn't exist
 * Thread-safe using PostgreSQL's ON CONFLICT
 */
export async function incrementUsage(
  period: PeriodType,
  incrementBy: number = 1,
  date: Date = new Date()
): Promise<number> {
  const periodKey = getPeriodKey(date, period);

  // Use UPSERT with PostgreSQL's ON CONFLICT to handle race conditions
  const [result] = await db
    .insert(adzunaUsage)
    .values({
      period,
      period_key: periodKey,
      request_count: incrementBy,
    })
    .onConflictDoUpdate({
      target: [adzunaUsage.period, adzunaUsage.period_key],
      set: {
        request_count: sql`${adzunaUsage.request_count} + ${incrementBy}`,
      },
    })
    .returning({ request_count: adzunaUsage.request_count });

  return result?.request_count ?? incrementBy;
}

/**
 * Increment all periods atomically
 * Returns new counts for each period
 */
export async function incrementAllPeriods(
  incrementBy: number = 1,
  date: Date = new Date()
): Promise<Record<PeriodType, number>> {
  const periods: PeriodType[] = ['daily', 'weekly', 'monthly'];
  
  const results = await Promise.all(
    periods.map(async (period) => {
      const newCount = await incrementUsage(period, incrementBy, date);
      return [period, newCount] as const;
    })
  );

  return Object.fromEntries(results) as Record<PeriodType, number>;
}

/**
 * Check if any quota limits have been reached
 * Returns true if ALL quotas are within limits
 */
export async function checkQuotaLimits(
  limits: { daily: number; weekly: number; monthly: number },
  date: Date = new Date()
): Promise<{ allowed: boolean; usage: Record<PeriodType, number>; exceeded?: PeriodType }> {
  const usage = await getAllUsage(date);

  if (usage.daily >= limits.daily) {
    return { allowed: false, usage, exceeded: 'daily' };
  }
  
  if (usage.weekly >= limits.weekly) {
    return { allowed: false, usage, exceeded: 'weekly' };
  }
  
  if (usage.monthly >= limits.monthly) {
    return { allowed: false, usage, exceeded: 'monthly' };
  }

  return { allowed: true, usage };
}

/**
 * In-memory cache for usage counts
 * Reduces database queries during a single import run
 * Cache is invalidated after incrementing
 */
class UsageCache {
  private cache: Map<string, { count: number; timestamp: number }> = new Map();
  private ttlMs = 60000; // 1 minute cache TTL

  getCacheKey(period: PeriodType, date: Date): string {
    return `${period}:${getPeriodKey(date, period)}`;
  }

  get(period: PeriodType, date: Date): number | null {
    const key = this.getCacheKey(period, date);
    const cached = this.cache.get(key);
    
    if (!cached) return null;
    
    // Check if cache is still valid
    if (Date.now() - cached.timestamp > this.ttlMs) {
      this.cache.delete(key);
      return null;
    }
    
    return cached.count;
  }

  set(period: PeriodType, date: Date, count: number): void {
    const key = this.getCacheKey(period, date);
    this.cache.set(key, { count, timestamp: Date.now() });
  }

  invalidate(period: PeriodType, date: Date): void {
    const key = this.getCacheKey(period, date);
    this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }
}

export const usageCache = new UsageCache();

/**
 * Get usage with caching
 * Reads from cache first, falls back to database
 */
export async function getUsageCached(period: PeriodType, date: Date = new Date()): Promise<number> {
  const cached = usageCache.get(period, date);
  if (cached !== null) return cached;

  const count = await getUsage(period, date);
  usageCache.set(period, date, count);
  return count;
}

/**
 * Increment usage and invalidate cache
 */
export async function incrementUsageCached(
  period: PeriodType,
  incrementBy: number = 1,
  date: Date = new Date()
): Promise<number> {
  const newCount = await incrementUsage(period, incrementBy, date);
  usageCache.invalidate(period, date);
  usageCache.set(period, date, newCount);
  return newCount;
}

interface CacheEntry<T> {
  data: T;
  timestamp: number;
  expiresAt: number;
}

class SimpleCache {
  private cache = new Map<string, CacheEntry<any>>();
  private defaultTTL = 60 * 60 * 1000; // 1 hour in milliseconds

  set<T>(key: string, data: T, ttl?: number): void {
    const now = Date.now();
    const expiresAt = now + (ttl || this.defaultTTL);

    this.cache.set(key, {
      data,
      timestamp: now,
      expiresAt,
    });
  }

  get<T>(key: string): T | null {
    const entry = this.cache.get(key);

    if (!entry) {
      return null;
    }

    // Check if expired
    if (Date.now() > entry.expiresAt) {
      this.cache.delete(key);
      return null;
    }

    return entry.data as T;
  }

  clear(): void {
    this.cache.clear();
  }

  delete(key: string): void {
    this.cache.delete(key);
  }
}

export const adzunaCache = new SimpleCache();

import { AdzunaSearchParams, AdzunaSearchResponse } from './types';
import dotenv from 'dotenv';

const ADZUNA_BASE_URL = 'https://api.adzuna.com/v1/api';

class AdzunaClient {
  private appId: string;
  private appKey: string;
  private baseUrl: string;

  constructor(country: string = 'us') {
    // Load .env.local for local script usage
    if (typeof window === 'undefined' && !process.env.ADZUNA_APP_ID) {
      dotenv.config({ path: '.env.local' });
    }

    this.appId = process.env.ADZUNA_APP_ID || '';
    this.appKey = process.env.ADZUNA_APP_KEY || '';
    this.baseUrl = `${ADZUNA_BASE_URL}/jobs/${country}`;

    if (!this.appId || !this.appKey) {
      throw new Error(
        'Adzuna credentials not found. Set ADZUNA_APP_ID and ADZUNA_APP_KEY.'
      );
    }
  }

  private buildSearchUrl(params: AdzunaSearchParams): string {
    const { 
      what = '', 
      where = '', 
      page = 1,
      results_per_page = 20,
      sort_by = 'relevance',
      ...otherParams 
    } = params;

    const url = new URL(`${this.baseUrl}/search/${page}`);

    url.searchParams.append('app_id', this.appId);
    url.searchParams.append('app_key', this.appKey);
    url.searchParams.append('results_per_page', results_per_page.toString());
    url.searchParams.append('sort_by', sort_by);

    if (what) url.searchParams.append('what', what);
    if (where) url.searchParams.append('where', where);

    Object.entries(otherParams).forEach(([key, value]) => {
      if (value !== undefined && value !== null) {
        url.searchParams.append(key, value.toString());
      }
    });

    return url.toString();
  }

  async search(params: AdzunaSearchParams): Promise<AdzunaSearchResponse> {
    const url = this.buildSearchUrl(params);
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Adzuna API error: ${response.status}`);
    }
    return response.json();
  }

  async getTopRoles(limit = 10): Promise<AdzunaSearchResponse> {
    return this.search({ results_per_page: limit, sort_by: 'relevance' });
  }

  async searchByRole(roleName: string): Promise<AdzunaSearchResponse> {
    return this.search({ what: roleName, results_per_page: 20, sort_by: 'relevance' });
  }
}

/**
 * Lazy-initialized Adzuna client.
 * Only throws if credentials are missing when you actually USE it,
 * not when the module is imported. This prevents build-time crashes
 * on Vercel where ADZUNA_APP_ID isn't set.
 */
let _client: AdzunaClient | null = null;
export function getAdzunaClient(country = 'us'): AdzunaClient {
  if (country !== 'us') return new AdzunaClient(country);
  if (!_client) _client = new AdzunaClient();
  return _client;
}

// Backwards-compatible proxy: defers instantiation until first property access
export const adzunaClient = new Proxy({} as AdzunaClient, {
  get(_, prop) {
    return (getAdzunaClient() as any)[prop];
  },
});

// lib/geocoding-service.ts
// Reusable geocoding service for both batch scripts and API imports

interface GeocodingResult {
  lat: number;
  lng: number;
}

interface GeocodingCache {
  [key: string]: GeocodingResult | null;
}

/**
 * In-memory cache for geocoding results
 * Prevents duplicate API calls for the same location
 */
const geocodingCache: GeocodingCache = {};

/**
 * Create a cache key from location components
 */
function getCacheKey(city: string, state?: string | null, country?: string | null): string {
  return [city, state, country]
    .filter(Boolean)
    .map(s => s?.toLowerCase().trim())
    .join('|');
}

/**
 * Geocode using OpenStreetMap Nominatim (Free)
 * Rate limit: 1 request per second
 * Documentation: https://nominatim.org/release-docs/latest/api/Search/
 */
export async function geocodeWithNominatim(
  city: string,
  state?: string | null,
  country?: string | null
): Promise<GeocodingResult | null> {
  const cacheKey = getCacheKey(city, state, country);
  
  // Check cache first
  if (cacheKey in geocodingCache) {
    return geocodingCache[cacheKey];
  }

  try {
    const query = [city, state, country].filter(Boolean).join(', ');
    const url = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(
      query
    )}&format=json&limit=1`;

    const response = await fetch(url, {
      headers: {
        'User-Agent': 'JobPostingsAnalysisApp/1.0',
      },
    });

    if (!response.ok) {
      console.error(`Nominatim HTTP error! status: ${response.status}`);
      geocodingCache[cacheKey] = null;
      return null;
    }

    const data = await response.json();

    if (data && data[0]) {
      const result = {
        lat: parseFloat(data[0].lat),
        lng: parseFloat(data[0].lon),
      };
      geocodingCache[cacheKey] = result;
      return result;
    }

    geocodingCache[cacheKey] = null;
    return null;
  } catch (error) {
    console.error('Nominatim geocoding error:', error);
    geocodingCache[cacheKey] = null;
    return null;
  }
}

/**
 * Geocode using Google Maps Geocoding API (Paid, more accurate)
 * Requires GOOGLE_MAPS_API_KEY in environment
 * Pricing: $5 per 1000 requests, $200/month free credit
 * Documentation: https://developers.google.com/maps/documentation/geocoding
 */
export async function geocodeWithGoogle(
  city: string,
  state?: string | null,
  country?: string | null
): Promise<GeocodingResult | null> {
  const apiKey = process.env.GOOGLE_MAPS_API_KEY;

  if (!apiKey) {
    console.warn('GOOGLE_MAPS_API_KEY not set');
    return null;
  }

  const cacheKey = getCacheKey(city, state, country);

  // Check cache first
  if (cacheKey in geocodingCache) {
    return geocodingCache[cacheKey];
  }

  try {
    const address = [city, state, country].filter(Boolean).join(', ');
    const url = `https://maps.googleapis.com/maps/api/geocode/json?address=${encodeURIComponent(
      address
    )}&key=${apiKey}`;

    const response = await fetch(url);
    const data = await response.json();

    if (data.status === 'OK' && data.results[0]) {
      const location = data.results[0].geometry.location;
      const result = {
        lat: location.lat,
        lng: location.lng,
      };
      geocodingCache[cacheKey] = result;
      return result;
    }

    if (data.status === 'ZERO_RESULTS') {
      geocodingCache[cacheKey] = null;
    }

    console.warn(`Google geocoding failed: ${data.status}`);
    return null;
  } catch (error) {
    console.error('Google geocoding error:', error);
    return null;
  }
}

/**
 * Geocode using Mapbox (Alternative paid service)
 * Requires MAPBOX_ACCESS_TOKEN in environment
 * Pricing: 100,000 free requests/month, then $0.75 per 1000
 * Documentation: https://docs.mapbox.com/api/search/geocoding/
 */
export async function geocodeWithMapbox(
  city: string,
  state?: string | null,
  country?: string | null
): Promise<GeocodingResult | null> {
  const accessToken = process.env.MAPBOX_ACCESS_TOKEN;

  if (!accessToken) {
    console.warn('MAPBOX_ACCESS_TOKEN not set');
    return null;
  }

  const cacheKey = getCacheKey(city, state, country);

  if (cacheKey in geocodingCache) {
    return geocodingCache[cacheKey];
  }

  try {
    const query = [city, state, country].filter(Boolean).join(', ');
    const url = `https://api.mapbox.com/geocoding/v5/mapbox.places/${encodeURIComponent(
      query
    )}.json?access_token=${accessToken}&limit=1`;

    const response = await fetch(url);
    const data = await response.json();

    if (data.features && data.features[0]) {
      const [lng, lat] = data.features[0].center;
      const result = { lat, lng };
      geocodingCache[cacheKey] = result;
      return result;
    }

    geocodingCache[cacheKey] = null;
    return null;
  } catch (error) {
    console.error('Mapbox geocoding error:', error);
    return null;
  }
}

/**
 * Smart geocoding with fallback strategy
 * Tries services in order: Google → Mapbox → Nominatim
 */
export async function geocodeLocation(
  city: string,
  state?: string | null,
  country?: string | null
): Promise<GeocodingResult | null> {
  // Try Google Maps first (best accuracy)
  if (process.env.GOOGLE_MAPS_API_KEY) {
    const result = await geocodeWithGoogle(city, state, country);
    if (result) return result;
  }

  // Try Mapbox second (good accuracy, generous free tier)
  if (process.env.MAPBOX_ACCESS_TOKEN) {
    const result = await geocodeWithMapbox(city, state, country);
    if (result) return result;
  }

  // Fall back to Nominatim (free, lower rate limits)
  return await geocodeWithNominatim(city, state, country);
}

/**
 * Batch geocode multiple locations with rate limiting
 * Useful for importing many locations at once
 */
export async function batchGeocode(
  locations: Array<{
    city: string;
    state?: string | null;
    country?: string | null;
  }>,
  delayMs: number = 1000
): Promise<Array<GeocodingResult | null>> {
  const results: Array<GeocodingResult | null> = [];

  for (const location of locations) {
    const result = await geocodeLocation(
      location.city,
      location.state,
      location.country
    );
    results.push(result);

    // Rate limiting
    if (delayMs > 0) {
      await new Promise((resolve) => setTimeout(resolve, delayMs));
    }
  }

  return results;
}

/**
 * Clear the geocoding cache
 * Useful for testing or memory management
 */
export function clearGeocodingCache(): void {
  Object.keys(geocodingCache).forEach((key) => delete geocodingCache[key]);
}

/**
 * Get cache statistics
 */
export function getGeocodingCacheStats() {
  const entries = Object.entries(geocodingCache);
  return {
    total: entries.length,
    successful: entries.filter(([_, v]) => v !== null).length,
    failed: entries.filter(([_, v]) => v === null).length,
  };
}

import React from "react";
import {
  Code,
  Briefcase,
  User,
  Truck,
  Stethoscope,
  Tag,
  Activity,
  ShoppingCart,
} from "lucide-react";

// Lightweight mapping of role keywords to lucide icons
const ICON_MAP: Array<[RegExp, React.ElementType]> = [
  [/engineer|developer|software|frontend|backend|programmer/i, Code],
  [/sales|account|business|executive|salesperson/i, Briefcase],
  [/manager|lead|director/i, User],
  [/retail|store|shop|cashier/i, ShoppingCart],
  [/nurse|health|medical|doctor/i, Stethoscope],
  [/marketing|brand|content/i, Tag],
  [/operations|ops|logistics/i, Truck],
  [/trend|analytics|data/i, Activity],
];

export function pickIconForRole(role: string) {
  for (const [re, Icon] of ICON_MAP) if (re.test(role)) return Icon;
  return Briefcase;
}

export function colorFromString(s: string) {
  const palette = [
    "#7c3aed", // purple
    "#06b6d4", // cyan
    "#f97316", // orange
    "#10b981", // green
    "#ef4444", // red
    "#2563eb", // blue
  ];
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (h * 31 + s.charCodeAt(i)) >>> 0;
  return palette[h % palette.length];
}

export function fgForBg(hex: string) {
  // compute luminance and return white or dark foreground
  const c = hex.substring(1);
  const bigint = parseInt(c, 16);
  const r = (bigint >> 16) & 255;
  const g = (bigint >> 8) & 255;
  const b = bigint & 255;
  const luminance = 0.2126 * r + 0.7152 * g + 0.0722 * b;
  return luminance < 140 ? "#fff" : "#0f172a";
}

export default null;

/**
 * Create a URL-friendly slug from location string
 * "San Francisco, CA, USA" -> "san-francisco-ca-usa"
 */
export function slugifyLocation(location: string | null): string {
  if (!location) return '';
  
  return location
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

/**
 * Parse a location string into components
 */
export function parseLocation(location: string) {
  const parts = location.split(',').map(p => p.trim());
  
  return {
    city: parts[0] || '',
    state: parts[1] || '',
    country: parts[2] || parts[1] || '',
  };
}

/**
 * Geocode location to lat/lng using OpenStreetMap Nominatim
 * Free tier, no API key required
 */
export async function geocodeLocation(
  city: string, 
  state?: string, 
  country?: string
): Promise<{ lat: number; lng: number } | null> {
  try {
    const query = [city, state, country].filter(Boolean).join(', ');
    const url = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(query)}&format=json&limit=1`;
    
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'JobPostingsAnalysisApp/1.0',
      },
    });
    
    const data = await response.json();
    
    if (data && data[0]) {
      return {
        lat: parseFloat(data[0].lat),
        lng: parseFloat(data[0].lon),
      };
    }
    
    return null;
  } catch (error) {
    console.error('Geocoding error:', error);
    return null;
  }
}

/**
 * Format salary for display
 */
export function formatSalary(salary: number | null): string {
  if (!salary) return 'N/A';
  
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(salary);
}

// Map full state names to abbreviations - same as in the page component
export const STATE_ABBREVIATIONS: Record<string, string> = {
  'alabama': 'al', 'alaska': 'ak', 'arizona': 'az', 'arkansas': 'ar',
  'california': 'ca', 'colorado': 'co', 'connecticut': 'ct', 'delaware': 'de',
  'florida': 'fl', 'georgia': 'ga', 'hawaii': 'hi', 'idaho': 'id',
  'illinois': 'il', 'indiana': 'in', 'iowa': 'ia', 'kansas': 'ks',
  'kentucky': 'ky', 'louisiana': 'la', 'maine': 'me', 'maryland': 'md',
  'massachusetts': 'ma', 'michigan': 'mi', 'minnesota': 'mn', 'mississippi': 'ms',
  'missouri': 'mo', 'montana': 'mt', 'nebraska': 'ne', 'nevada': 'nv',
  'new hampshire': 'nh', 'new jersey': 'nj', 'new mexico': 'nm', 'new york': 'ny',
  'north carolina': 'nc', 'north dakota': 'nd', 'ohio': 'oh', 'oklahoma': 'ok',
  'oregon': 'or', 'pennsylvania': 'pa', 'rhode island': 'ri', 'south carolina': 'sc',
  'south dakota': 'sd', 'tennessee': 'tn', 'texas': 'tx', 'utah': 'ut',
  'vermont': 'vt', 'virginia': 'va', 'washington': 'wa', 'west virginia': 'wv',
  'wisconsin': 'wi', 'wyoming': 'wy',
  'district of columbia': 'dc', 'puerto rico': 'pr'
};

/**
 * Generate a location slug that matches the database format
 * Database uses: city-stateAbbrev (e.g., "san-francisco-ca")
 * NOT: city-fullStateName-country
 */
export function generateLocationSlug(
  city?: string | null,
  state?: string | null,
  country?: string | null
): string {
  const parts: string[] = [];

  // Add city
  if (city) {
    parts.push(
      city
        .toLowerCase()
        .trim()
        .replace(/\s+/g, '-')
        .replace(/[^a-z0-9-]/g, '')
        .replace(/-+/g, '-')
        .replace(/^-|-$/g, '')
    );
  }

  // Add state (abbreviated if full name)
  if (state) {
    const stateLower = state.toLowerCase().trim();
    const stateSlug = stateLower
      .replace(/\s+/g, '-')
      .replace(/[^a-z0-9-]/g, '')
      .replace(/-+/g, '-')
      .replace(/^-|-$/g, '');
    
    // Check if it's a full state name that needs abbreviation
    const abbreviated = STATE_ABBREVIATIONS[stateLower] || 
                       STATE_ABBREVIATIONS[stateSlug] || 
                       stateSlug;
    
    parts.push(abbreviated);
  }

  // Note: We're NOT adding country to match the database format
  // The database uses city-state format (e.g., "san-francisco-ca")

  return parts.join('-');
}

/**
 * Alternative: If you want to keep country codes in URLs but need them
 * to work with the database, you can strip them in the detail page
 */
export function normalizeLocationSlug(slug: string): string {
  const parts = slug.split('-');
  
  // If it looks like city-state-country (ends with 2-char country code)
  if (parts.length >= 3 && parts[parts.length - 1].length === 2) {
    // Check if second-to-last part is a full state name
    const potentialState = parts[parts.length - 2];
    if (STATE_ABBREVIATIONS[potentialState]) {
      // Replace full state with abbreviation and remove country
      const newParts = [...parts];
      newParts[newParts.length - 2] = STATE_ABBREVIATIONS[potentialState];
      return newParts.slice(0, -1).join('-'); // Remove country code
    }
    
    // Otherwise just remove the country code
    return parts.slice(0, -1).join('-');
  }
  
  return slug;
}

